import React, { useState, useEffect, useCallback } from 'react';
import { Bell, Check, Trash2 } from 'lucide-react';
import api from '../api/axiosInstance';
import { toast } from 'react-hot-toast';
import type { Notification } from '../types/mess';

const NotificationCenter: React.FC = () => {
    const [notifications, setNotifications] = useState<Notification[]>([]);
    const [isOpen, setIsOpen] = useState(false);
    const [unreadCount, setUnreadCount] = useState(0);

    const fetchNotifications = useCallback(async () => {
        try {
            const response = await api.get('/notifications');
            setNotifications(response.data.data);
            setUnreadCount(response.data.data.filter((n: Notification) => !n.read).length);
        } catch (err) {
            console.error('Failed to fetch notifications', err);
        }
    }, []);

    useEffect(() => {
        fetchNotifications();

        const interval = setInterval(fetchNotifications, 60000);
        return () => clearInterval(interval);
    }, [fetchNotifications]);

    const markAsRead = async (id: string) => {
        try {
            await api.put(`/notifications/${id}/read`);
            fetchNotifications();
        } catch (err) {
            console.error('Failed to mark notification as read', err);
            toast.error('Failed to mark as read');
        }
    };

    const deleteNotification = async (id: string) => {
        try {
            await api.delete(`/notifications/${id}`);
            fetchNotifications();
            toast.success('Notification deleted');
        } catch (err) {
            console.error('Failed to delete notification', err);
            toast.error('Failed to delete notification');
        }
    };

    return (
        <div className="relative">
            <button
                onClick={() => setIsOpen(!isOpen)}
                className="relative p-2 rounded-xl bg-gray-100 hover:bg-gray-200 transition-colors"
            >
                <Bell size={20} className="text-gray-600" />
                {unreadCount > 0 && (
                    <span className="absolute -top-1 -right-1 w-5 h-5 bg-primary text-white text-[10px] font-black flex items-center justify-center rounded-full border-2 border-white animate-bounce">
                        {unreadCount}
                    </span>
                )}
            </button>

            {isOpen && (
                <>
                    <div
                        className="fixed inset-0 z-40"
                        onClick={() => setIsOpen(false)}
                    />
                    <div className="absolute right-0 mt-4 w-80 md:w-96 bg-white rounded-2xl shadow-2xl border border-gray-100 overflow-hidden z-50 animate-in fade-in zoom-in-95 duration-200">
                        <div className="p-4 bg-gray-50 border-b border-gray-100 flex justify-between items-center">
                            <h3 className="font-black text-sm uppercase tracking-widest">Notifications</h3>
                            {unreadCount > 0 && (
                                <button
                                    onClick={() => markAsRead('all')}
                                    className="text-[10px] font-black text-primary uppercase hover:underline"
                                >
                                    Mark all as read
                                </button>
                            )}
                        </div>

                        <div className="max-h-[400px] overflow-y-auto divide-y divide-gray-50">
                            {notifications.length > 0 ? (
                                notifications.map(n => (
                                    <div
                                        key={n.id}
                                        className={`p-4 flex gap-4 hover:bg-gray-50 transition-colors relative group ${!n.read ? 'bg-primary/5' : ''}`}
                                    >
                                        <div className={`mt-1 h-2 w-2 rounded-full shrink-0 ${!n.read ? 'bg-primary' : 'bg-transparent'}`} />
                                        <div className="flex-grow">
                                            <p className="text-sm font-bold text-gray-900 leading-tight">{n.title}</p>
                                            <p className="text-xs text-gray-500 mt-1">{n.message}</p>
                                            <p className="text-[10px] text-gray-400 font-medium mt-2">
                                                {n.created_at ? new Date(n.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : 'N/A'}
                                            </p>
                                        </div>
                                        <div className="opacity-0 group-hover:opacity-100 transition-opacity flex flex-col gap-2">
                                            {!n.read && (
                                                <button onClick={() => markAsRead(n.id)} className="p-1 text-green-500 hover:bg-green-50 rounded-md">
                                                    <Check size={14} />
                                                </button>
                                            )}
                                            <button onClick={() => deleteNotification(n.id)} className="p-1 text-red-400 hover:bg-red-50 rounded-md">
                                                <Trash2 size={14} />
                                            </button>
                                        </div>
                                    </div>
                                ))
                            ) : (
                                <div className="p-12 text-center">
                                    <Bell size={32} className="mx-auto text-gray-200 mb-2" />
                                    <p className="text-xs font-bold text-gray-400 uppercase tracking-widest">No notifications yet</p>
                                </div>
                            )}
                        </div>
                    </div>
                </>
            )}
        </div>
    );
};

export default NotificationCenter;

import React, { createContext, useContext, useState, useEffect } from 'react';
import api from '../api/axiosInstance';
import type { Mess } from '../types/mess';
import { useAppSelector } from '../../hooks/redux';
import type { RootState } from '../../store';

interface FavoritesContextType {
    favorites: string[];
    toggleFavorite: (messId: string) => Promise<boolean>;
    isFavorite: (messId: string) => boolean;
    loading: boolean;
}

const FavoritesContext = createContext<FavoritesContextType | undefined>(undefined);

export const FavoritesProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [favorites, setFavorites] = useState<string[]>([]);
    const [loading, setLoading] = useState(false);
    const { token, user } = useAppSelector((state: RootState) => state.auth);

    useEffect(() => {
        const fetchFavorites = async () => {
            if (!token || !user) { // Check for user as well
                setFavorites([]);
                return;
            }
            setLoading(true);
            try {
                const response = await api.get('/favorites');
                if (response.data.success) {
                    const ids = response.data.data.map((m: Mess) => String(m.id)); // Use Mess type
                    setFavorites(ids);
                }
            } catch (error) {
                console.error('Error fetching favorites:', error);
            } finally {
                setLoading(false);
            }
        };

        fetchFavorites();
    }, [token, user]);

    const toggleFavorite = async (messId: string) => {
        const id = String(messId);

        if (!token) {
            alert('Please login to favorite messes!');
            window.location.href = '/login';
            return false;
        }

        // Optimistic update
        const wasFavorite = favorites.includes(id);
        if (wasFavorite) {
            setFavorites(prev => prev.filter(fid => fid !== id));
        } else {
            setFavorites(prev => [...prev, id]);
        }

        try {
            const response = await api.post(`/favorites/toggle/${id}`);
            if (response.data.success) {
                // Keep the sync with server just in case
                if (response.data.isFavorite) {
                    setFavorites(prev => prev.includes(id) ? prev : [...prev, id]);
                } else {
                    setFavorites(prev => prev.filter(fid => fid !== id));
                }
                return response.data.isFavorite;
            }
        } catch (error) {
            // Revert on error
            if (wasFavorite) {
                setFavorites(prev => prev.includes(id) ? prev : [...prev, id]);
            } else {
                setFavorites(prev => prev.filter(fid => fid !== id));
            }
            console.error('Error toggling favorite:', error);
            alert('Could not update favorite. Please check your connection.');
        }
        return false;
    };

    const isFavorite = (messId: string | undefined) => {
        if (!messId) return false;
        return favorites.includes(String(messId));
    };

    return (
        <FavoritesContext.Provider value={{ favorites, toggleFavorite, isFavorite, loading }}>
            {children}
        </FavoritesContext.Provider>
    );
};

export const useFavorites = () => {
    const context = useContext(FavoritesContext);
    if (context === undefined) {
        throw new Error('useFavorites must be used within a FavoritesProvider');
    }
    return context;
};

import React, { useState } from 'react';
import { Layout } from '../components/layout/Layout';
import { Button } from '../components/common/Button';
import { Card } from '../components/common/Card';
import {
    Utensils,
    MapPin,
    Phone,
    User,
    IndianRupee,
    FileText,
    Image as ImageIcon,
    Upload,
    X,
    CheckCircle2,
    ArrowRight,
    Loader2
} from 'lucide-react';
import { motion } from 'framer-motion';
import api from '../api/axiosInstance';
import { useNavigate, Link } from 'react-router-dom';
import Seo from '../components/common/Seo';
import { useEffect } from 'react';

const AddMessPage: React.FC = () => {
    const navigate = useNavigate();
    const [loading, setLoading] = useState(false);
    const [subStatus, setSubStatus] = useState<string | null>(null);
    const [success, setSuccess] = useState(false);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        const checkSub = async () => {
            try {
                const res = await api.get('/subscriptions/status');
                if (res.data.data) {
                    const status = res.data.data.status;
                    // Check if trial/active date is actually valid
                    const now = new Date();
                    const end = status === 'trial' ? new Date(res.data.data.trial_end_date) : new Date(res.data.data.subscription_end);

                    if (end < now) {
                        setSubStatus('expired');
                    } else {
                        setSubStatus(status);
                    }
                } else {
                    setSubStatus('none');
                }
            } catch (err) {
                console.error('Failed to check subscription', err);
            } finally {
                // Done check
            }
        };
        checkSub();
    }, []);

    // Form State
    const [formData, setFormData] = useState({
        messName: '',
        ownerName: '',
        mobile: '',
        address: '',
        pricePerMonth: '',
        pricePerWeek: '',
        pricePerDay: '',
        menuText: ''
    });

    const [messImage, setMessImage] = useState<File | null>(null);
    const [menuImages, setMenuImages] = useState<File[]>([]);
    const [previews, setPreviews] = useState<{ mess: string | null; menus: string[] }>({
        mess: null,
        menus: []
    });

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleMessImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            setMessImage(file);
            setPreviews(prev => ({ ...prev, mess: URL.createObjectURL(file) }));
        }
    };

    const handleMenuImagesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = Array.from(e.target.files || []);
        if (files.length + menuImages.length > 5) {
            alert('Maximum 5 menu images allowed');
            return;
        }
        const newFiles = [...menuImages, ...files];
        setMenuImages(newFiles);
        setPreviews(prev => ({
            ...prev,
            menus: newFiles.map(f => URL.createObjectURL(f))
        }));
    };

    const removeMenuImage = (index: number) => {
        const newFiles = [...menuImages];
        newFiles.splice(index, 1);
        setMenuImages(newFiles);
        setPreviews(prev => ({
            ...prev,
            menus: newFiles.map(f => URL.createObjectURL(f))
        }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError(null);

        const data = new FormData();
        Object.entries(formData).forEach(([key, value]) => {
            data.append(key, value);
        });

        if (messImage) {
            data.append('mess_image', messImage);
        }
        menuImages.forEach(file => {
            data.append('menu_images', file);
        });

        try {
            await api.post('/mess', data, {
                headers: { 'Content-Type': 'multipart/form-data' }
            });
            setSuccess(true);
            setTimeout(() => navigate('/find-mess'), 3000);
        } catch (error) {
            const err = error as any;
            console.error('Registration failed:', err);
            setError(err.response?.data?.message || 'Failed to register mess. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    if (success) {
        return (
            <Layout>
                <div className="min-h-[80vh] flex items-center justify-center">
                    <motion.div
                        initial={{ scale: 0.9, opacity: 0 }}
                        animate={{ scale: 1, opacity: 1 }}
                        className="text-center space-y-8 p-12 bg-white/5 backdrop-blur-3xl rounded-[3rem] border border-white/10 shadow-3xl max-w-lg w-full"
                    >
                        <div className="w-24 h-24 bg-primary-500/20 rounded-full flex items-center justify-center mx-auto">
                            <CheckCircle2 size={48} className="text-primary-500" />
                        </div>
                        <div className="space-y-4">
                            <h2 className="text-4xl font-black italic tracking-tighter text-white uppercase">Mess Registered!</h2>
                            <p className="text-white/40 font-bold uppercase tracking-widest text-xs">Your mess has been added to the network successfully. Redirecting to exploration page...</p>
                        </div>
                    </motion.div>
                </div>
            </Layout>
        );
    }

    return (
        <Layout>
            <Seo
                title="Register Your Mess | MessWalha"
                description="Join the elite network of student mess services. Register your mess and reach thousands of students today."
            />

            {subStatus === 'expired' && (
                <div className="bg-red-500 py-4 text-center relative z-50">
                    <p className="text-white font-black uppercase tracking-[0.2em] text-[10px] md:text-xs flex items-center justify-center gap-4">
                        <X size={16} />
                        Your Subscription has expired. Please subscribe to continue publishing.
                        <Link to="/owner/subscribe" className="bg-white text-red-500 px-4 py-1 rounded-full hover:bg-white/90 transition-all font-black">Subscribe Now</Link>
                    </p>
                </div>
            )}

            <div className="grad-dark py-32 relative overflow-hidden">
                <div className="container mx-auto px-4 relative z-10 text-center">
                    <motion.h1
                        initial={{ y: 20, opacity: 0 }}
                        animate={{ y: 0, opacity: 1 }}
                        className="text-6xl md:text-8xl font-black tracking-tighter text-white italic"
                    >
                        Join the <span className="text-primary-500">Elite</span> Network
                    </motion.h1>
                    <p className="text-white/40 font-black uppercase tracking-[0.4em] text-[10px] md:text-xs">Register your mess service on MessWalha</p>
                </div>
            </div>

            <div className="container mx-auto px-4 py-24">
                <motion.form
                    initial={{ y: 40, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    onSubmit={handleSubmit}
                    className="max-w-4xl mx-auto space-y-12"
                >
                    {error && (
                        <div className="bg-red-500/10 border border-red-500/20 text-red-500 p-6 rounded-2xl text-xs font-black uppercase tracking-widest">
                            {error}
                        </div>
                    )}

                    {/* Section 1: Basic Details */}
                    <Card className="p-12 space-y-10 bg-white/5 backdrop-blur-3xl border-white/10 rounded-[3rem]">
                        <div className="flex items-center gap-4 text-primary-500">
                            <Utensils size={24} />
                            <h3 className="text-xl font-black uppercase tracking-widest italic">Basic Details</h3>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            <div className="space-y-3">
                                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40 ml-2">Mess Name</label>
                                <div className="relative group">
                                    <Utensils size={16} className="absolute left-6 top-1/2 -translate-y-1/2 text-primary-500" />
                                    <input
                                        type="text"
                                        name="messName"
                                        required
                                        placeholder="E.G. SAI DARBAR MESS"
                                        className="w-full bg-white/[0.03] border border-white/10 text-white pl-14 pr-6 py-5 rounded-2xl focus:ring-2 focus:ring-primary-500/50 outline-none transition-all font-bold tracking-widest text-xs"
                                        value={formData.messName}
                                        onChange={handleInputChange}
                                    />
                                </div>
                            </div>
                            <div className="space-y-3">
                                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40 ml-2">Owner Name</label>
                                <div className="relative group">
                                    <User size={16} className="absolute left-6 top-1/2 -translate-y-1/2 text-primary-500" />
                                    <input
                                        type="text"
                                        name="ownerName"
                                        required
                                        placeholder="FULL NAME"
                                        className="w-full bg-white/[0.03] border border-white/10 text-white pl-14 pr-6 py-5 rounded-2xl focus:ring-2 focus:ring-primary-500/50 outline-none transition-all font-bold tracking-widest text-xs"
                                        value={formData.ownerName}
                                        onChange={handleInputChange}
                                    />
                                </div>
                            </div>
                            <div className="space-y-3">
                                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40 ml-2">Mobile Number</label>
                                <div className="relative group">
                                    <Phone size={16} className="absolute left-6 top-1/2 -translate-y-1/2 text-primary-500" />
                                    <input
                                        type="tel"
                                        name="mobile"
                                        required
                                        placeholder="10 DIGIT NUMBER"
                                        className="w-full bg-white/[0.03] border border-white/10 text-white pl-14 pr-6 py-5 rounded-2xl focus:ring-2 focus:ring-primary-500/50 outline-none transition-all font-bold tracking-widest text-xs"
                                        value={formData.mobile}
                                        onChange={handleInputChange}
                                    />
                                </div>
                            </div>
                            <div className="space-y-3">
                                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40 ml-2">Mess Address</label>
                                <div className="relative group">
                                    <MapPin size={16} className="absolute left-6 top-1/2 -translate-y-1/2 text-primary-500" />
                                    <input
                                        type="text"
                                        name="address"
                                        required
                                        placeholder="AREA / NEAR COLLEGE"
                                        className="w-full bg-white/[0.03] border border-white/10 text-white pl-14 pr-6 py-5 rounded-2xl focus:ring-2 focus:ring-primary-500/50 outline-none transition-all font-bold tracking-widest text-xs"
                                        value={formData.address}
                                        onChange={handleInputChange}
                                    />
                                </div>
                            </div>
                        </div>
                    </Card>

                    {/* Section 2: Pricing */}
                    <Card className="p-12 space-y-10 bg-white/5 backdrop-blur-3xl border-white/10 rounded-[3rem]">
                        <div className="flex items-center gap-4 text-primary-500">
                            <IndianRupee size={24} />
                            <h3 className="text-xl font-black uppercase tracking-widest italic">Pricing Details</h3>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                            <div className="space-y-3">
                                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40 ml-2">Cost Per Month</label>
                                <div className="relative group">
                                    <IndianRupee size={16} className="absolute left-6 top-1/2 -translate-y-1/2 text-primary-500" />
                                    <input
                                        type="number"
                                        name="pricePerMonth"
                                        required
                                        placeholder="Γé╣ 3000"
                                        className="w-full bg-white/[0.03] border border-white/10 text-white pl-14 pr-6 py-5 rounded-2xl focus:ring-2 focus:ring-primary-500/50 outline-none transition-all font-bold tracking-widest text-xs"
                                        value={formData.pricePerMonth}
                                        onChange={handleInputChange}
                                    />
                                </div>
                            </div>
                            <div className="space-y-3">
                                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40 ml-2">Cost Per Week</label>
                                <div className="relative group">
                                    <IndianRupee size={16} className="absolute left-6 top-1/2 -translate-y-1/2 text-primary-500" />
                                    <input
                                        type="number"
                                        name="pricePerWeek"
                                        required
                                        placeholder="Γé╣ 800"
                                        className="w-full bg-white/[0.03] border border-white/10 text-white pl-14 pr-6 py-5 rounded-2xl focus:ring-2 focus:ring-primary-500/50 outline-none transition-all font-bold tracking-widest text-xs"
                                        value={formData.pricePerWeek}
                                        onChange={handleInputChange}
                                    />
                                </div>
                            </div>
                            <div className="space-y-3">
                                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40 ml-2">Cost Per Day</label>
                                <div className="relative group">
                                    <IndianRupee size={16} className="absolute left-6 top-1/2 -translate-y-1/2 text-primary-500" />
                                    <input
                                        type="number"
                                        name="pricePerDay"
                                        required
                                        placeholder="Γé╣ 120"
                                        className="w-full bg-white/[0.03] border border-white/10 text-white pl-14 pr-6 py-5 rounded-2xl focus:ring-2 focus:ring-primary-500/50 outline-none transition-all font-bold tracking-widest text-xs"
                                        value={formData.pricePerDay}
                                        onChange={handleInputChange}
                                    />
                                </div>
                            </div>
                        </div>
                    </Card>

                    {/* Section 3: Menu & Photos */}
                    <Card className="p-12 space-y-12 bg-white/5 backdrop-blur-3xl border-white/10 rounded-[4rem]">
                        <div className="flex items-center gap-4 text-primary-500">
                            <FileText size={24} />
                            <h3 className="text-xl font-black uppercase tracking-widest italic">Menu & Media</h3>
                        </div>

                        <div className="space-y-12">
                            {/* Text Menu */}
                            <div className="space-y-4">
                                <div className="flex items-center justify-between">
                                    <label className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40 ml-2">Menu Description (Optional)</label>
                                    <span className="text-[8px] font-black uppercase tracking-widest text-primary-500/60 bg-primary-500/5 px-3 py-1 rounded-full border border-primary-500/10">Text Option</span>
                                </div>
                                <textarea
                                    name="menuText"
                                    placeholder="MONDAY: POHA, DAL RICE..."
                                    rows={4}
                                    className="w-full bg-white/[0.03] border border-white/10 text-white px-8 py-6 rounded-3xl focus:ring-2 focus:ring-primary-500/50 outline-none transition-all font-bold tracking-widest text-xs"
                                    value={formData.menuText}
                                    onChange={handleInputChange}
                                />
                            </div>

                            {/* Main Image */}
                            <div className="space-y-6">
                                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40 ml-2">Mess Display Photo (Plate Image)</label>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                    <div
                                        onClick={() => document.getElementById('messImageInput')?.click()}
                                        className="h-64 border-2 border-dashed border-white/10 rounded-[2rem] flex flex-col items-center justify-center gap-4 hover:border-primary-500/50 hover:bg-white/5 cursor-pointer transition-all group overflow-hidden relative"
                                    >
                                        {previews.mess ? (
                                            <img src={previews.mess} className="absolute inset-0 w-full h-full object-cover opacity-60 group-hover:scale-110 transition-transform duration-700" alt="Preview" />
                                        ) : (
                                            <>
                                                <Upload size={32} className="text-white/10 group-hover:text-primary-500 transition-colors" />
                                                <span className="text-[9px] font-black uppercase tracking-widest text-white/20">Click to Upload</span>
                                            </>
                                        )}
                                        <input
                                            id="messImageInput"
                                            type="file"
                                            hidden
                                            accept="image/*"
                                            onChange={handleMessImageChange}
                                        />
                                    </div>
                                    <div className="flex flex-col justify-center space-y-4 pr-8">
                                        <div className="flex items-center gap-3 text-primary-500">
                                            <ImageIcon size={16} />
                                            <h4 className="text-[10px] font-black uppercase tracking-widest">Main Display Signal</h4>
                                        </div>
                                        <p className="text-[10px] font-medium leading-relaxed text-white/30 italic">
                                            This will be the first image students see when browsing. We recommend a clear photo of your special meal plate.
                                        </p>
                                    </div>
                                </div>
                            </div>

                            {/* Menu Images */}
                            <div className="space-y-6">
                                <div className="flex items-center justify-between">
                                    <label className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40 ml-2">Gallery / Menu Board Photos (Max 5)</label>
                                    <span className="text-[8px] font-black uppercase tracking-widest text-primary-500/60 bg-primary-500/5 px-3 py-1 rounded-full border border-primary-500/10">Image Option</span>
                                </div>
                                <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-6 gap-6">
                                    {previews.menus.map((url, i) => (
                                        <div key={i} className="aspect-square rounded-2xl overflow-hidden relative group border border-white/10">
                                            <img src={url} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" alt={`Menu ${i}`} />
                                            <button
                                                type="button"
                                                onClick={() => removeMenuImage(i)}
                                                className="absolute top-2 right-2 w-6 h-6 bg-red-500 rounded-full flex items-center justify-center text-white opacity-0 group-hover:opacity-100 transition-opacity"
                                            >
                                                <X size={12} />
                                            </button>
                                        </div>
                                    ))}
                                    {menuImages.length < 5 && (
                                        <div
                                            onClick={() => document.getElementById('menuImagesInput')?.click()}
                                            className="aspect-square border-2 border-dashed border-white/10 rounded-2xl flex flex-col items-center justify-center gap-2 hover:border-primary-500/50 hover:bg-white/5 cursor-pointer transition-all group"
                                        >
                                            <Upload size={20} className="text-white/10 group-hover:text-primary-500" />
                                            <span className="text-[8px] font-black uppercase tracking-widest text-white/20">Add</span>
                                            <input
                                                id="menuImagesInput"
                                                type="file"
                                                multiple
                                                hidden
                                                accept="image/*"
                                                onChange={handleMenuImagesChange}
                                            />
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </Card>

                    <div className="flex justify-center pt-8">
                        <Button
                            type="submit"
                            size="lg"
                            disabled={loading || subStatus === 'expired'}
                            className="h-24 px-20 rounded-[2rem] bg-primary-500 text-white font-black uppercase tracking-[0.4em] text-sm shadow-3xl shadow-primary-500/40 hover:scale-[1.05] transition-all disabled:opacity-50 flex items-center gap-4"
                        >
                            {loading ? (
                                <Loader2 className="animate-spin" />
                            ) : (
                                <>
                                    Submit Mess Registry
                                    <ArrowRight size={20} />
                                </>
                            )}
                        </Button>
                    </div>
                </motion.form>
            </div>
        </Layout>
    );
};

export default AddMessPage;

import React, { useState, useEffect } from 'react';
import { Layout } from '../components/layout/Layout';
import { Card } from '../components/common/Card';
import { Button } from '../components/common/Button';
import {
    Shield,
    Users,
    Building,
    Activity,
    CircleCheck,
    Trash2,
    UserPlus,
    Search,
    LayoutDashboard,
    Settings as SettingsIcon,
    RefreshCw,
    Eye
} from 'lucide-react';
import api from '../api/axiosInstance';
import { toast } from 'react-hot-toast';
import type { Mess, User } from '../types/mess';

type AdminTab = 'overview' | 'users' | 'messes' | 'settings';

const AdminDashboardPage: React.FC = () => {
    const [activeTab, setActiveTab] = useState<AdminTab>('overview');
    const [stats, setStats] = useState<Record<string, any> | null>(null);
    const [users, setUsers] = useState<User[]>([]);
    const [messes, setMesses] = useState<Mess[]>([]);
    const [loading, setLoading] = useState(true);
    const [refreshing, setRefreshing] = useState(false);

    const fetchData = async () => {
        try {
            setLoading(true);
            const [statsRes, usersRes, messesRes] = await Promise.all([
                api.get('/admin/stats'),
                api.get('/admin/users'),
                api.get('/admin/messes')
            ]);
            setStats(statsRes.data.data);
            setUsers(usersRes.data.data);
            setMesses(messesRes.data.data);
        } catch (err) {
            toast.error('Failed to load admin data');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchData();
    }, []);

    const handleVerifyMess = async (id: string, currentStatus: boolean) => {
        try {
            await api.put(`/admin/messes/${id}/verify`, { verified: !currentStatus });
            setMesses(prev => prev.map(m => m.id === id ? { ...m, verified: !currentStatus } : m));
            toast.success('Mess verification status updated');
        } catch (err) {
            toast.error('Failed to update verification status');
        }
    };

    const handleDeleteUser = async (id: string) => {
        if (!window.confirm('Are you sure you want to delete this user? This action cannot be undone.')) return;
        try {
            await api.delete(`/admin/users/${id}`);
            setUsers(prev => prev.filter(u => u.id !== id));
            toast.success('User deleted successfully');
        } catch (err) {
            console.error('Error fetching stats:', err);
        }
    };

    const renderOverview = () => (
        <div className="space-y-12">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                {[
                    { label: 'Total Users', value: stats?.users || 0, icon: <Users />, color: 'bg-indigo-500' },
                    { label: 'Total Messes', value: stats?.messes || 0, icon: <Building />, color: 'bg-primary' },
                    { label: 'Active Subs', value: stats?.activeSubscriptions || 0, icon: <Activity />, color: 'bg-emerald-500' },
                    { label: 'Revenue', value: `Γé╣${(stats?.totalRevenue || 0).toLocaleString()}`, icon: <Shield />, color: 'bg-amber-500' },
                    { label: 'Total Visits', value: (stats?.totalVisits || 0).toLocaleString(), icon: <Eye />, color: 'bg-rose-500' },
                ].map((item, i) => (
                    <Card key={i} className="p-6 border-none shadow-xl hover:scale-[1.02] transition-transform">
                        <div className="flex items-center space-x-4">
                            <div className={`p-4 rounded-2xl text-white shadow-lg shadow-black/10 ${item.color}`}>
                                {item.icon}
                            </div>
                            <div>
                                <p className="text-xs text-gray-400 font-black uppercase tracking-widest">{item.label}</p>
                                <p className="text-2xl font-black mt-1">{item.value}</p>
                            </div>
                        </div>
                    </Card>
                ))}
            </div>

            <section className="space-y-4">
                <h3 className="text-lg font-black uppercase tracking-widest flex items-center gap-2">
                    <Activity size={18} className="text-primary" /> Owner Subscriptions
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    {[
                        { label: 'Free Trials', value: stats?.ownerStats?.trial || 0, color: 'text-orange-500', bg: 'bg-orange-50' },
                        { label: 'Active (Paid)', value: stats?.ownerStats?.active || 0, color: 'text-green-500', bg: 'bg-green-50' },
                        { label: 'Expired', value: stats?.ownerStats?.expired || 0, color: 'text-red-500', bg: 'bg-red-50' },
                    ].map((item, i) => (
                        <Card key={i} className="p-6 border-none shadow-lg">
                            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">{item.label}</p>
                            <div className="flex items-end justify-between">
                                <p className={`text-4xl font-black ${item.color}`}>{item.value}</p>
                                <div className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${item.bg} ${item.color}`}>
                                    Status
                                </div>
                            </div>
                        </Card>
                    ))}
                </div>
            </section>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <section className="space-y-4">
                    <h3 className="text-lg font-black uppercase tracking-widest flex items-center gap-2">
                        <UserPlus size={18} className="text-primary" /> Recent Users
                    </h3>
                    <Card className="p-0 overflow-hidden">
                        <div className="divide-y divide-gray-100">
                            {users.slice(0, 5).map(u => (
                                <div key={u.id} className="p-4 flex items-center justify-between hover:bg-gray-50 transition-colors">
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 rounded-full bg-indigo-50 text-indigo-500 flex items-center justify-center font-bold">
                                            {u.name.charAt(0)}
                                        </div>
                                        <div>
                                            <p className="font-bold text-sm">{u.name}</p>
                                            <p className="text-xs text-gray-400">{u.role}</p>
                                        </div>
                                    </div>
                                    <span className="text-[10px] text-gray-400">{u.createdAt ? new Date(u.createdAt).toLocaleDateString() : 'N/A'}</span>
                                </div>
                            ))}
                        </div>
                    </Card>
                </section>

                <section className="space-y-4">
                    <h3 className="text-lg font-black uppercase tracking-widest flex items-center gap-2">
                        <Building size={18} className="text-secondary" /> Pending Verifications
                    </h3>
                    <Card className="p-0 overflow-hidden">
                        <div className="divide-y divide-gray-100">
                            {messes.filter(m => !m.verified).slice(0, 5).map(m => (
                                <div key={m.id} className="p-4 flex items-center justify-between hover:bg-gray-50 transition-colors">
                                    <div>
                                        <p className="font-bold text-sm">{m.name}</p>
                                        <p className="text-xs text-gray-400">Owner: {m.owner?.name || 'N/A'}</p>
                                    </div>
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        className="text-[10px] font-black uppercase py-1 h-8"
                                        onClick={() => handleVerifyMess(m.id, false)}
                                    >
                                        Verify
                                    </Button>
                                </div>
                            ))}
                            {messes.filter(m => !m.verified).length === 0 && (
                                <div className="p-12 text-center text-gray-400">
                                    <CircleCheck size={32} className="mx-auto mb-2 opacity-20" />
                                    <p className="text-xs font-bold uppercase tracking-widest">All Verified!</p>
                                </div>
                            )}
                        </div>
                    </Card>
                </section>
            </div>
        </div>
    );

    const renderUsers = () => (
        <div className="space-y-4">
            <div className="flex justify-between items-center bg-white p-4 rounded-2xl shadow-sm">
                <div className="relative flex-grow max-w-md">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                    <input type="text" placeholder="Search users by name or email..." className="w-full pl-12 pr-4 py-3 rounded-xl bg-gray-50 border-none text-sm font-medium" />
                </div>
            </div>
            <Card className="p-0 overflow-hidden">
                <table className="w-full text-left">
                    <thead className="bg-gray-50 border-b border-gray-100">
                        <tr>
                            <th className="px-6 py-4 text-xs font-black uppercase tracking-widest text-gray-400">User</th>
                            <th className="px-6 py-4 text-xs font-black uppercase tracking-widest text-gray-400">Role</th>
                            <th className="px-6 py-4 text-xs font-black uppercase tracking-widest text-gray-400">Joined</th>
                            <th className="px-6 py-4 text-xs font-black uppercase tracking-widest text-gray-400 text-right">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {users.map(u => (
                            <tr key={u.id} className="hover:bg-gray-50/50 transition-colors">
                                <td className="px-6 py-4">
                                    <div className="flex items-center gap-3">
                                        <div className="w-8 h-8 rounded-lg bg-gray-100 flex items-center justify-center font-bold text-xs">
                                            {u.name[0]}
                                        </div>
                                        <div>
                                            <p className="font-bold text-sm">{u.name}</p>
                                            <p className="text-xs text-gray-400">{u.email}</p>
                                        </div>
                                    </div>
                                </td>
                                <td className="px-6 py-4">
                                    <span className={`px-2 py-1 rounded-md text-[9px] font-black uppercase ${u.role === 'ADMIN' ? 'bg-indigo-100 text-indigo-600' : u.role === 'OWNER' ? 'bg-amber-100 text-amber-600' : 'bg-emerald-100 text-emerald-600'}`}>
                                        {u.role}
                                    </span>
                                </td>
                                <td className="px-6 py-4 text-xs font-medium text-gray-500">
                                    {u.createdAt ? new Date(u.createdAt).toLocaleDateString() : 'N/A'}
                                </td>
                                <td className="px-6 py-4 text-right">
                                    <Button variant="ghost" size="sm" className="text-red-500 hover:bg-red-50" onClick={() => handleDeleteUser(u.id)}>
                                        <Trash2 size={16} />
                                    </Button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </Card>
        </div>
    );

    const renderMesses = () => (
        <div className="grid grid-cols-1 gap-4">
            {messes.map(m => (
                <Card key={m.id} className="p-6 flex flex-col md:row items-center justify-between gap-6 hover:border-primary transition-colors group">
                    <div className="flex items-center gap-6 flex-grow">
                        <div className="w-16 h-16 rounded-2xl bg-gray-100 overflow-hidden relative">
                            {m.images?.[0] ? (
                                <img
                                    src={m.images[0]}
                                    alt={m.name}
                                    className="w-full h-full object-cover"
                                    onError={(e) => {
                                        (e.target as HTMLImageElement).src = 'https://via.placeholder.com/400x300.png?text=Mess+Image';
                                    }}
                                />
                            ) : (
                                <Building className="w-full h-full p-4 text-gray-300" />
                            )}
                        </div>
                        <div>
                            <div className="flex items-center gap-2">
                                <h4 className="font-black text-lg">{m.name}</h4>
                                {m.verified && <CircleCheck size={14} className="text-green-500" />}
                            </div>
                            <p className="text-xs text-gray-400 font-bold uppercase tracking-wider">{m.cuisine} ΓÇó {m.address}</p>
                            <p className="text-[10px] text-gray-500 font-medium mt-1">Owner: {m.owner?.name || 'N/A'} ({m.owner?.email || 'N/A'})</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-12 text-center">
                        <div>
                            <p className="text-[10px] font-black text-gray-400 uppercase">Subs</p>
                            <p className="text-lg font-black">{m._count?.subscriptions || 0}</p>
                        </div>
                        <div>
                            <p className="text-[10px] font-black text-gray-400 uppercase">Reviews</p>
                            <p className="text-lg font-black">{m._count?.reviews || 0}</p>
                        </div>
                        <div className="flex gap-2">
                            <Button
                                variant={m.verified ? "outline" : "primary"}
                                size="sm"
                                className="rounded-xl px-6 text-[10px] font-black uppercase"
                                onClick={() => handleVerifyMess(m.id, m.verified || false)}
                            >
                                {m.verified ? 'Revoke' : 'Verify'}
                            </Button>
                        </div>
                    </div>
                </Card>
            ))}
        </div>
    );

    return (
        <Layout>
            <div className="bg-dark text-white py-12 relative overflow-hidden">
                <div className="absolute inset-0 bg-primary opacity-5 animate-pulse" />
                <div className="container mx-auto px-4 relative">
                    <div className="flex flex-col md:row items-center justify-between gap-6">
                        <div className="space-y-2">
                            <h1 className="text-4xl font-heading font-black tracking-tighter">ADMIN PANEL</h1>
                            <div className="flex items-center space-x-2 text-primary">
                                <Shield size={16} />
                                <p className="text-sm font-bold uppercase tracking-widest">Platform Infrastructure</p>
                            </div>
                        </div>
                        <Button
                            variant="outline"
                            size="sm"
                            className="rounded-xl border-white/20 text-white hover:bg-white/10"
                            onClick={() => {
                                setRefreshing(true);
                                fetchData().then(() => setRefreshing(false));
                            }}
                        >
                            <RefreshCw size={18} className={`mr-2 ${refreshing ? 'animate-spin' : ''}`} /> Refresh Data
                        </Button>
                    </div>
                </div>
            </div>

            <div className="container mx-auto px-4 -mt-10 pb-20">
                <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
                    <div className="lg:col-span-1">
                        <Card className="p-2 space-y-1 sticky top-24 shadow-2xl rounded-2xl dark:bg-dark-card border-none">
                            {[
                                { id: 'overview', icon: <LayoutDashboard size={20} />, label: 'Overview' },
                                { id: 'users', icon: <Users size={20} />, label: 'User Management' },
                                { id: 'messes', icon: <Building size={20} />, label: 'Mess Verification' },
                                { id: 'settings', icon: <SettingsIcon size={20} />, label: 'Platform Stats' },
                            ].map((item) => (
                                <button
                                    key={item.id}
                                    onClick={() => setActiveTab(item.id as AdminTab)}
                                    className={`w-full flex items-center space-x-3 px-5 py-4 rounded-xl transition-all font-bold text-sm ${activeTab === item.id
                                        ? 'bg-primary text-white shadow-xl shadow-primary/30'
                                        : 'text-gray-500 hover:bg-gray-50'
                                        }`}
                                >
                                    {item.icon}
                                    <span>{item.label}</span>
                                </button>
                            ))}
                        </Card>
                    </div>

                    <div className="lg:col-span-3">
                        {loading && !refreshing ? (
                            <div className="space-y-6">
                                <div className="grid grid-cols-4 gap-6">
                                    {[1, 2, 3, 4].map(i => <div key={i} className="h-24 bg-gray-100 rounded-2xl animate-pulse" />)}
                                </div>
                                <div className="h-96 bg-gray-100 rounded-2xl animate-pulse" />
                            </div>
                        ) : (
                            <>
                                {activeTab === 'overview' && renderOverview()}
                                {activeTab === 'users' && renderUsers()}
                                {activeTab === 'messes' && renderMesses()}
                                {activeTab === 'settings' && (
                                    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                                        <Card className="p-8 border-none shadow-2xl bg-gradient-to-br from-white to-gray-50 dark:from-dark-card dark:to-dark">
                                            <div className="flex flex-col md:row items-center justify-between gap-8">
                                                <div className="space-y-4 text-center md:text-left">
                                                    <h3 className="text-2xl font-black tracking-tight flex items-center gap-3">
                                                        <Activity className="text-primary" /> Platform Performance
                                                    </h3>
                                                    <p className="text-gray-500 font-medium max-w-md">
                                                        Real-time tracking of platform activity and visitor engagement.
                                                    </p>
                                                </div>
                                                <div className="flex gap-4">
                                                    <div className="p-6 rounded-3xl bg-primary/5 border border-primary/10 text-center min-w-[160px]">
                                                        <p className="text-[10px] font-black text-primary uppercase tracking-widest mb-1">Total Visits</p>
                                                        <p className="text-3xl font-black text-primary">{(stats?.totalVisits || 0).toLocaleString()}</p>
                                                    </div>
                                                </div>
                                            </div>
                                        </Card>

                                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                            {[
                                                { label: 'New Users Today', value: '0', icon: <Users />, color: 'text-indigo-500' },
                                                { label: 'Server Status', value: 'Online', icon: <Activity />, color: 'text-emerald-500' },
                                                { label: 'Database Status', value: 'Connected', icon: <Shield />, color: 'text-amber-500' },
                                            ].map((item, i) => (
                                                <Card key={i} className="p-6 border-none shadow-xl hover:shadow-2xl transition-all">
                                                    <div className="flex items-center gap-4">
                                                        <div className={`p-3 rounded-xl bg-gray-50 ${item.color}`}>
                                                            {item.icon}
                                                        </div>
                                                        <div>
                                                            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{item.label}</p>
                                                            <p className="text-lg font-black">{item.value}</p>
                                                        </div>
                                                    </div>
                                                </Card>
                                            ))}
                                        </div>
                                    </div>
                                )}
                            </>
                        )}
                    </div>
                </div>
            </div>
        </Layout>
    );
};

export default AdminDashboardPage;

import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { Button } from '../components/common/Button';
import { Input } from '../components/common/Input';
import { Card } from '../components/common/Card';
import { Utensils, ArrowLeft, CircleCheck, AlertCircle } from 'lucide-react';
import api from '../api/axiosInstance';
import { toast } from 'react-hot-toast';

const ForgotPasswordPage: React.FC = () => {
    const [email, setEmail] = useState('');
    const [isSubmitted, setIsSubmitted] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        setError(null);

        try {
            await api.post('/auth/forgot-password', { email });
            setIsSubmitted(true);
        } catch (error) {
            const err = error as any;
            const message = err.response?.data?.message || 'Failed to send reset link. Please try again.';
            setError(message);
            toast.error(message);
        } finally {
            setIsLoading(false);
        }
    };

    if (isSubmitted) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-dark px-4 py-12">
                <Card className="w-full max-w-md p-8 text-center space-y-6">
                    <div className="w-20 h-20 bg-green-50 text-green-500 rounded-full flex items-center justify-center mx-auto mb-4">
                        <CircleCheck size={40} />
                    </div>
                    <h1 className="text-3xl font-heading font-bold">Check Your Email</h1>
                    <p className="text-gray-500">
                        We've sent password reset instructions to <span className="font-bold text-gray-900">{email}</span>.
                    </p>
                    <Link to="/login">
                        <Button className="w-full mt-4">Return to Login</Button>
                    </Link>
                </Card>
            </div>
        );
    }

    return (
        <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-dark px-4 py-12">
            <Card className="w-full max-w-md p-8">
                <div className="text-center space-y-2 mb-8">
                    <Link to="/" className="inline-flex items-center justify-center p-3 bg-primary rounded-xl text-white mb-4">
                        <Utensils size={32} />
                    </Link>
                    <h1 className="text-3xl font-heading font-bold">Forgot Password?</h1>
                    <p className="text-gray-500">Enter your email and we'll send you a link to reset your password.</p>
                </div>

                {error && (
                    <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-xl flex items-start gap-3 text-red-600 animate-in fade-in slide-in-from-top-2">
                        <AlertCircle className="shrink-0 mt-0.5" size={18} />
                        <p className="text-sm font-medium">{error}</p>
                    </div>
                )}

                <form onSubmit={handleSubmit} className="space-y-6">
                    <Input
                        label="Email Address"
                        type="email"
                        placeholder="name@example.com"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        required
                    />

                    <Button type="submit" className="w-full" size="lg" isLoading={isLoading}>
                        Send Reset Link
                    </Button>

                    <Link to="/login" className="flex items-center justify-center text-sm text-gray-400 hover:text-primary transition-colors gap-2">
                        <ArrowLeft size={16} />
                        Back to Sign In
                    </Link>
                </form>
            </Card>
        </div>
    );
};

export default ForgotPasswordPage;

import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Button } from '../components/common/Button';
import { Input } from '../components/common/Input';
import { Card } from '../components/common/Card';
import { Utensils } from 'lucide-react';
import { useAppDispatch } from '../../hooks/redux';
import { setCredentials } from '../../store/slices/authSlice';
import api from '../api/axiosInstance';

const LoginPage: React.FC = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [isLoading, setIsLoading] = useState(false);

    const dispatch = useAppDispatch();
    const navigate = useNavigate();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        setError('');

        try {
            // Call backend directly for login
            const response = await api.post('/auth/login', { email, password });

            dispatch(setCredentials(response.data));
            navigate('/');
        } catch (error) {
            const err = error as any;
            console.error('Login error:', err);
            const errorMessage = err.response?.data?.message || err.response?.data?.error || 'Login failed. Please try again.';
            setError(errorMessage);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-dark px-4 py-12">
            <Card className="w-full max-w-md p-8">
                <div className="text-center space-y-2 mb-8">
                    <Link to="/" className="inline-flex items-center justify-center p-3 bg-primary rounded-xl text-white mb-4">
                        <Utensils size={32} />
                    </Link>
                    <h1 className="text-3xl font-heading font-bold">Welcome Back</h1>
                    <p className="text-gray-500">Sign in to your MessWalha account</p>
                </div>

                <form onSubmit={handleSubmit} className="space-y-6">
                    {error && (
                        <div className="bg-red-50 text-red-500 p-3 rounded-lg text-sm border border-red-100">
                            {error}
                        </div>
                    )}

                    <div className="space-y-4">
                        <Input
                            label="Email Address"
                            type="email"
                            placeholder="name@example.com"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            required
                        />
                        <Input
                            label="Password"
                            type="password"
                            placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                        />
                    </div>

                    <div className="flex items-center justify-between">
                        <label className="flex items-center space-x-2 text-sm">
                            <input type="checkbox" className="rounded border-gray-300 text-primary focus:ring-primary" />
                            <span>Remember me</span>
                        </label>
                        <Link to="/forgot-password" title="Forgot password" className="text-sm text-primary hover:underline">
                            Forgot password?
                        </Link>
                    </div>

                    <Button type="submit" className="w-full" size="lg" isLoading={isLoading}>
                        Sign In
                    </Button>
                </form>

                <div className="mt-8 pt-6 border-t border-gray-100 dark:border-dark-lighter text-center">
                    <p className="text-sm text-gray-500">
                        Don't have an account?{' '}
                        <Link to="/register" className="text-primary font-semibold hover:underline">
                            Create an account
                        </Link>
                    </p>
                </div>
            </Card>
        </div>
    );
};

export default LoginPage;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Layout } from '../components/layout/Layout';
import { Button } from '../components/common/Button';
import { Card } from '../components/common/Card';
import {
    Star,
    Clock,
    Utensils,
    CircleCheck,
    MessageSquare,
    Share2,
    Heart,
    User as UserIcon,
    Phone,
    Navigation,
    ShieldCheck
} from 'lucide-react';
import api, { getImageUrl } from '../api/axiosInstance';
import { useAppSelector } from '../../hooks/redux';
import type { RootState } from '../../store';
import { useFavorites } from '../context/FavoritesContext';
import { motion } from 'framer-motion';
import type { Mess, Menu } from '../types/mess';

declare global {
    interface Window {
        Razorpay: any;
    }
}

interface Plan {
    title: string;
    price: string;
    priceValue: number;
    type: string;
    period: string;
    desc: string;
    popular?: boolean;
}

interface RazorpayResponse {
    razorpay_payment_id: string;
    razorpay_order_id: string;
    razorpay_signature: string;
}

const MessDetailsPage: React.FC = () => {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const [mess, setMess] = useState<Mess | null>(null);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState<'menu' | 'reviews' | 'about'>('menu');
    const [selectedDay, setSelectedDay] = useState(new Date().toLocaleDateString('en-US', { weekday: 'long' }));
    const [selectedPlan, setSelectedPlan] = useState<Plan | null>(null);
    const [subscribing, setSubscribing] = useState(false);
    const [reviewForm, setReviewForm] = useState({ rating: 5, comment: '', show: false });
    const { isFavorite, toggleFavorite } = useFavorites();
    const { user } = useAppSelector((state: RootState) => state.auth);

    useEffect(() => {
        const fetchDetails = async () => {
            if (!id) return;
            try {
                const response = await api.get(`/messes/${id}`);
                setMess(response.data.data);
            } catch (error) {
                console.error('Error fetching details:', error);
            } finally {
                setLoading(false);
            }
        };

        fetchDetails();
    }, [id]);

    const handleSubscribe = async () => {
        if (!selectedPlan) {
            alert('Please select a plan first');
            return;
        }

        try {
            setSubscribing(true);
            const { data } = await api.post('/payments/create-order', {
                messId: id,
                planType: selectedPlan.type,
                amount: selectedPlan.priceValue
            });

            if (data.isTestMode) {
                try {
                    const verifyRes = await api.post('/payments/verify', {
                        razorpay_order_id: data.orderId,
                        razorpay_payment_id: 'mock_pay_' + Date.now(),
                        razorpay_signature: 'mock_sig',
                        messId: id,
                        planType: selectedPlan.type
                    });
                    if (verifyRes.data.success) {
                        alert('Subscription successful (Test Mode)');
                        navigate('/subscriptions');
                    }
                    return;
                } catch (verifyErr) {
                    console.error('Test verification failed', verifyErr);
                    alert('Mock payment failed');
                    return;
                }
            }

            const options = {
                key: import.meta.env.VITE_RAZORPAY_KEY_ID,
                amount: data.amount,
                currency: data.currency,
                name: 'MessWalha',
                description: `Subscription for ${mess?.name}`,
                order_id: data.orderId,
                handler: async (response: RazorpayResponse) => {
                    try {
                        const verifyRes = await api.post('/payments/verify', {
                            razorpay_order_id: response.razorpay_order_id,
                            razorpay_payment_id: response.razorpay_payment_id,
                            razorpay_signature: response.razorpay_signature,
                            messId: id,
                            planType: selectedPlan.type
                        });
                        if (verifyRes.data.success) {
                            alert('Subscription successful!');
                            navigate('/subscriptions');
                        }
                    } catch (err) {
                        console.error('Verification failed', err);
                        alert('Payment verification failed. Please contact support.');
                    }
                },
                prefill: {
                    name: user?.name || undefined,
                    email: user?.email || undefined,
                },
                theme: { color: '#F97316' }
            };

            const rzp = new window.Razorpay(options);
            rzp.open();
        } catch (error) {
            console.error('Checkout error', error);
            alert('Failed to initiate checkout');
        } finally {
            setSubscribing(false);
        }
    };

    const handleReviewSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            const { data } = await api.post('/reviews', {
                messId: id,
                rating: reviewForm.rating,
                comment: reviewForm.comment
            });
            if (data.success) {
                alert('Review submitted successfully!');
                setReviewForm({ rating: 5, comment: '', show: false });
                const response = await api.get(`/messes/${id}`);
                setMess(response.data.data);
            }
        } catch (error) {
            console.error('Review submission failed', error);
            alert('Failed to submit review. Make sure you are logged in.');
        }
    };

    if (loading) {
        return (
            <Layout>
                <div className="container mx-auto px-4 py-12 space-y-8 animate-pulse text-white">
                    <div className="h-64 bg-white/5 rounded-xl" />
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                        <div className="lg:col-span-2 space-y-6">
                            <div className="h-10 w-1/2 bg-white/5 rounded-md" />
                            <div className="h-4 w-3/4 bg-white/5 rounded-md" />
                            <div className="h-48 bg-white/5 rounded-xl" />
                        </div>
                        <div className="h-96 bg-white/5 rounded-xl" />
                    </div>
                </div>
            </Layout>
        );
    }

    if (!mess) return <Layout><div className="text-center py-20 text-white">Mess not found</div></Layout>;

    const currentDayMenu = mess.menus?.find((m: Menu) => m.day === selectedDay);
    const days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];

    return (
        <Layout>
            <div className="container mx-auto px-4 py-8 max-w-7xl">
                {/* Hero Section */}
                <div className="relative h-[300px] md:h-[450px] rounded-[2.5rem] overflow-hidden mb-12 shadow-2xl group">
                    <img
                        src={getImageUrl(mess.messImage || mess.images?.[0]) || 'https://images.unsplash.com/photo-1504674900247-0877df9cc836?auto=format&fit=crop&q=80&w=1200'}
                        className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-105"
                        alt={mess.name}
                        onError={(e) => {
                            (e.target as HTMLImageElement).src = 'https://via.placeholder.com/1200x800.png?text=Mess+Image';
                        }}
                    />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent" />

                    <div className="absolute top-6 right-6 flex gap-3">
                        <button
                            onClick={() => {
                                if (!mess) return;
                                if (navigator.share) {
                                    navigator.share({
                                        title: mess.name,
                                        text: `Check out ${mess.name} on MessWalha!`,
                                        url: window.location.href,
                                    }).catch(console.error);
                                } else {
                                    navigator.clipboard.writeText(window.location.href);
                                    alert('Link copied to clipboard!');
                                }
                            }}
                            className="p-3 bg-white/10 backdrop-blur-md rounded-2xl text-white hover:bg-white/20 transition-all border border-white/20"
                        >
                            <Share2 size={20} />
                        </button>
                        <button
                            onClick={() => {
                                if (id) toggleFavorite(id);
                            }}
                            className={`p-3 backdrop-blur-md rounded-2xl transition-all border ${isFavorite(id || '') ? 'bg-red-500 border-red-500 text-white' : 'bg-white/10 border-white/20 text-white hover:bg-white/20'}`}
                        >
                            <Heart size={20} fill={isFavorite(id || '') ? 'currentColor' : 'none'} className={isFavorite(id || '') ? 'animate-pulse' : ''} />
                        </button>
                    </div>

                    <div className="absolute bottom-10 left-10 right-10 flex flex-col md:flex-row justify-between items-end gap-6 text-white">
                        <div className="space-y-3">
                            <div className="flex items-center gap-2">
                                <span className="bg-primary-500 text-white text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-md shadow-sm">
                                    {mess.cuisine || 'Multi-Cuisine'}
                                </span>
                                <span className="bg-success-500 text-white text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-md shadow-sm flex items-center">
                                    <CircleCheck size={12} className="mr-1" /> Shield Protocol Active
                                </span>
                            </div>
                            <h1 className="text-4xl md:text-6xl font-black italic tracking-tighter uppercase">{mess.name}</h1>
                            <div className="flex flex-wrap items-center gap-6">
                                <div className="flex items-center gap-2">
                                    <div className="flex text-rating-color">
                                        {[1, 2, 3, 4, 5].map((s) => (
                                            <Star key={s} size={16} fill={s <= Math.round(mess.rating || 4) ? 'currentColor' : 'none'} />
                                        ))}
                                    </div>
                                    <span className="font-black text-white">{(mess.rating || 4.5).toFixed(1)}</span>
                                    <span className="text-white/60 text-xs font-bold uppercase tracking-widest">({mess.reviews?.length || 0} Signal Logs)</span>
                                </div>
                                <div className="flex items-center gap-2 text-white/80 font-bold uppercase tracking-widest text-xs">
                                    <Navigation size={18} className="text-primary-500" />
                                    <span>{mess.location?.address || mess.address}</span>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
                    <div className="lg:col-span-8 space-y-12">
                        {/* Custom Tabs */}
                        <div className="flex gap-8 border-b border-white/5">
                            {[
                                { id: 'menu', label: 'Menu Protocol', icon: Utensils },
                                { id: 'reviews', label: 'Public Feed', icon: MessageSquare },
                                { id: 'about', label: 'Asset Details', icon: ShieldCheck },
                            ].map((tab) => (
                                <button
                                    key={tab.id}
                                    onClick={() => setActiveTab(tab.id as any)}
                                    className={`flex items-center gap-2 pb-6 text-[10px] font-black uppercase tracking-[0.3em] transition-all relative ${activeTab === tab.id
                                        ? 'text-primary-500'
                                        : 'text-white/30 hover:text-white'
                                        }`}
                                >
                                    <tab.icon size={16} />
                                    {tab.label}
                                    {activeTab === tab.id && (
                                        <motion.div layoutId="tab-underline" className="absolute bottom-0 left-0 right-0 h-1 bg-primary-500 rounded-full" />
                                    )}
                                </button>
                            ))}
                        </div>

                        {activeTab === 'menu' && (
                            <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
                                {mess.description && (
                                    <Card className="p-10 bg-white/5 backdrop-blur-3xl border-white/10 rounded-[3rem] space-y-6">
                                        <h3 className="text-[10px] font-black uppercase tracking-[0.4em] text-primary-500 italic">Menu Description</h3>
                                        <p className="text-white/60 font-medium leading-relaxed italic border-l-4 border-primary-500/20 pl-6 py-2">
                                            "{mess.description}"
                                        </p>
                                    </Card>
                                )}

                                {mess.menuImages && mess.menuImages.length > 0 && (
                                    <div className="space-y-6">
                                        <h3 className="text-[10px] font-black uppercase tracking-[0.4em] text-primary-500 italic">Menu Gallery</h3>
                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                            {mess.menuImages.map((img: string, i: number) => (
                                                <div key={i} className="rounded-[2rem] overflow-hidden border border-white/10 shadow-3xl aspect-[4/3] group">
                                                    <img
                                                        src={getImageUrl(img)}
                                                        className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-[2s]"
                                                        alt={`Menu ${i}`}
                                                    />
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}

                                <div className="space-y-8">
                                    <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                                        {days.map((day) => (
                                            <button
                                                key={day}
                                                onClick={() => setSelectedDay(day)}
                                                className={`px-6 py-3 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all border ${selectedDay === day
                                                    ? 'bg-primary-500 border-primary-500 text-white shadow-xl shadow-primary-500/20'
                                                    : 'bg-white/5 border-white/5 text-white/30 hover:bg-white/10'
                                                    }`}
                                            >
                                                {day}
                                            </button>
                                        ))}
                                    </div>

                                    <Card className="p-10 bg-white/5 backdrop-blur-3xl border-white/10 rounded-[3rem]">
                                        <div className="flex items-center justify-between mb-10">
                                            <h3 className="text-lg font-black uppercase tracking-widest italic text-white">{selectedDay}'s Protocol</h3>
                                            <span className="bg-success-500/10 text-success-500 px-4 py-2 rounded-full text-[9px] font-black uppercase tracking-widest border border-success-500/20 italic">Fresh Logistics Verified</span>
                                        </div>

                                        {currentDayMenu ? (
                                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                                {currentDayMenu.items.map((item, idx) => (
                                                    <div key={idx} className="bg-white/5 p-6 rounded-2xl flex items-center gap-6 border border-white/5 hover:border-primary-500/30 transition-all group">
                                                        <div className="w-14 h-14 rounded-xl bg-primary-500/10 flex items-center justify-center text-primary-500 group-hover:scale-110 transition-transform">
                                                            <Utensils size={20} />
                                                        </div>
                                                        <div className="flex-1">
                                                            <h4 className="font-black text-white text-[11px] uppercase tracking-widest mb-1">{item.name}</h4>
                                                            <span className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full border ${item.type === 'Non-Veg' ? 'border-red-500/20 bg-red-500/10 text-red-500' : 'border-success-500/20 bg-success-500/10 text-success-500'}`}>
                                                                {item.type}
                                                            </span>
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                        ) : (
                                            <div className="text-center py-20 bg-white/5 rounded-[2.5rem] border-2 border-dashed border-white/5">
                                                <p className="text-white/20 font-black uppercase tracking-[0.2em] text-[10px] italic">No digital menu log detected for this day</p>
                                            </div>
                                        )}
                                    </Card>
                                </div>
                            </div>
                        )}

                        {activeTab === 'reviews' && (
                            <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
                                <div className="flex justify-between items-center px-4">
                                    <h3 className="text-xl font-black uppercase tracking-widest italic text-white">Public Feed</h3>
                                    <Button
                                        variant="outline"
                                        className="rounded-full font-black uppercase tracking-widest text-[9px] py-4 px-8 bg-white/5 border-white/10 hover:bg-white/10 text-white/60 hover:text-white"
                                        onClick={() => setReviewForm(prev => ({ ...prev, show: !prev.show }))}
                                    >
                                        {reviewForm.show ? 'Cancel Log' : 'Post Signal Log'}
                                    </Button>
                                </div>

                                {reviewForm.show && (
                                    <Card className="p-10 border-primary-500/20 bg-primary-500/5 rounded-[3rem] animate-in slide-in-from-top-4 duration-300">
                                        <form onSubmit={handleReviewSubmit} className="space-y-8">
                                            <div className="space-y-4">
                                                <label className="text-[10px] font-black uppercase tracking-[0.3em] text-white/40 ml-2">Signal Intensity (Rating)</label>
                                                <div className="flex gap-4 p-4 bg-white/5 rounded-3xl w-fit">
                                                    {[1, 2, 3, 4, 5].map((num) => (
                                                        <button
                                                            key={num}
                                                            type="button"
                                                            onClick={() => setReviewForm({ ...reviewForm, rating: num })}
                                                            className={`p-2 transition-all hover:scale-125 ${reviewForm.rating >= num ? 'text-primary-500' : 'text-white/10'}`}
                                                        >
                                                            <Star size={32} fill={reviewForm.rating >= num ? 'currentColor' : 'none'} />
                                                        </button>
                                                    ))}
                                                </div>
                                            </div>
                                            <div className="space-y-4">
                                                <label className="text-[10px] font-black uppercase tracking-[0.3em] text-white/40 ml-2">Logic Description (Comment)</label>
                                                <textarea
                                                    required
                                                    value={reviewForm.comment}
                                                    onChange={(e) => setReviewForm({ ...reviewForm, comment: e.target.value })}
                                                    placeholder="Enter your experience metrics..."
                                                    className="w-full bg-white/[0.03] border border-white/10 text-white px-8 py-6 rounded-3xl focus:ring-2 focus:ring-primary-500/50 outline-none transition-all font-bold tracking-widest text-xs min-h-[150px]"
                                                />
                                            </div>
                                            <Button type="submit" className="w-full h-20 rounded-[1.5rem] font-black uppercase tracking-[0.3em] text-xs shadow-3xl shadow-primary-500/40">Transmit Log</Button>
                                        </form>
                                    </Card>
                                )}

                                <div className="grid grid-cols-1 gap-8">
                                    {mess.reviews && mess.reviews.length > 0 ? (
                                        mess.reviews.map((review) => (
                                            <Card key={review.id} className="p-8 bg-white/5 backdrop-blur-3xl border-white/10 rounded-[2.5rem] group hover:border-primary-500/30 transition-all">
                                                <div className="flex justify-between items-start mb-6">
                                                    <div className="flex items-center gap-4">
                                                        <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-primary-500 to-indigo-600 flex items-center justify-center text-white font-black text-xs shadow-2xl">
                                                            {review.user?.name?.[0] || review.user_name?.[0] || 'U'}
                                                        </div>
                                                        <div>
                                                            <h4 className="font-black text-white text-[11px] uppercase tracking-widest">{review.user?.name || review.user_name}</h4>
                                                            <p className="text-[9px] text-white/30 font-black uppercase tracking-[0.2em]">
                                                                {review.createdAt ? new Date(review.createdAt).toLocaleDateString() : review.created_at ? new Date(review.created_at).toLocaleDateString() : 'Unknown Date'}
                                                            </p>
                                                        </div>
                                                    </div>
                                                    <div className="flex bg-primary-500/10 px-4 py-2 rounded-full items-center gap-2 border border-primary-500/20">
                                                        <Star size={14} className="text-primary-500 fill-primary-500" />
                                                        <span className="text-[10px] font-black text-primary-500 uppercase tracking-widest">{review.rating}.0</span>
                                                    </div>
                                                </div>
                                                <p className="text-white/60 font-medium leading-relaxed italic pr-12">"{review.comment}"</p>
                                            </Card>
                                        ))
                                    ) : (
                                        <div className="text-center py-24 opacity-20 text-white">
                                            <MessageSquare size={80} strokeWidth={1} className="mx-auto mb-6" />
                                            <p className="font-black uppercase tracking-[0.4em] text-[10px] italic">No signal logs detected in this sector</p>
                                        </div>
                                    )}
                                </div>
                            </div>
                        )}

                        {activeTab === 'about' && (
                            <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                    <Card className="p-10 bg-white/5 backdrop-blur-3xl border-white/10 rounded-[3rem] space-y-8">
                                        <h4 className="font-black uppercase tracking-[0.4em] text-primary-500 italic text-[10px]">Shield Protocol</h4>
                                        <div className="space-y-4">
                                            {['Supply Chain Integrity', 'Hygiene Protocol', 'Unlimited Meal Access', 'Student Subsidies', 'Digital Payments'].map(f => (
                                                <div key={f} className="flex items-center gap-4 text-white/50 text-[10px] font-black uppercase tracking-widest italic group">
                                                    <CircleCheck size={18} className="text-primary-500 group-hover:scale-125 transition-transform" />
                                                    {f}
                                                </div>
                                            ))}
                                        </div>
                                    </Card>
                                    <Card className="p-10 bg-white/5 backdrop-blur-3xl border-white/10 rounded-[3rem] space-y-8">
                                        <h4 className="font-black uppercase tracking-[0.4em] text-primary-500 italic text-[10px]">Asset Operator</h4>
                                        <div className="space-y-6">
                                            <div className="flex items-center gap-5 group">
                                                <div className="w-14 h-14 rounded-2xl bg-white/5 flex items-center justify-center text-primary-500 border border-white/10 group-hover:scale-110 transition-transform shadow-2xl">
                                                    <UserIcon size={20} />
                                                </div>
                                                <div>
                                                    <p className="font-black text-white/20 uppercase tracking-[0.2em] text-[8px] mb-1">Operator Name</p>
                                                    <p className="text-xs font-black text-white uppercase tracking-widest">{mess.ownerName || mess.owner?.name}</p>
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-5 group">
                                                <div className="w-14 h-14 rounded-2xl bg-white/5 flex items-center justify-center text-primary-500 border border-white/10 group-hover:scale-110 transition-transform shadow-2xl">
                                                    <Phone size={20} />
                                                </div>
                                                <div>
                                                    <p className="font-black text-white/20 uppercase tracking-[0.2em] text-[8px] mb-1">Contact Signal</p>
                                                    <p className="text-xs font-black text-white uppercase tracking-widest">{mess.contact || mess.mobile}</p>
                                                </div>
                                            </div>
                                            <Button
                                                className="w-full h-16 rounded-2xl text-[9px] font-black uppercase tracking-[0.3em] bg-white/5 border border-white/10 hover:bg-white/10 text-white"
                                                onClick={async () => {
                                                    try {
                                                        await api.post('/chats', { ownerId: mess.ownerId });
                                                        navigate('/messages');
                                                    } catch (err) {
                                                        console.error('Chat error:', err);
                                                        alert('Shield error: Failed to initialize encrypted comms');
                                                    }
                                                }}
                                            >
                                                Initialize Comms
                                            </Button>
                                        </div>
                                    </Card>
                                </div>
                            </div>
                        )}
                    </div>

                    {/* Right Column: Sticky Sidebar */}
                    <div className="lg:col-span-4 lg:sticky lg:top-32 h-fit space-y-10">
                        <Card className="p-12 bg-white/5 backdrop-blur-3xl border-white/10 rounded-[4rem] shadow-3xl relative overflow-hidden group">
                            <div className="absolute top-0 right-0 w-32 h-32 bg-primary-500/10 rounded-full blur-3xl -mr-16 -mt-16 group-hover:scale-150 transition-transform duration-1000" />

                            <div className="text-center space-y-4 mb-12">
                                <h3 className="text-2xl font-black italic tracking-tighter uppercase text-white">Subscription</h3>
                                <div className="h-1 w-12 bg-primary-500 mx-auto rounded-full" />
                                <p className="text-white/20 text-[9px] font-black uppercase tracking-[0.3em]">Select Protocol Level</p>
                            </div>

                            <div className="space-y-4 mb-12">
                                {[
                                    { title: 'Elite Access', price: `Γé╣${mess.monthlyPrice || 2500}`, priceValue: mess.monthlyPrice || 2500, type: 'MONTHLY', period: '/month', popular: true, desc: '30 Cycle Supply + Shield' },
                                    { title: 'Sector Sprint', price: `Γé╣${mess.weeklyPrice || (Math.round((mess.monthlyPrice || 2500) / 4))}`, priceValue: mess.weeklyPrice || (Math.round((mess.monthlyPrice || 2500) / 4)), type: 'WEEKLY', period: '/week', desc: '7 Cycle Deployment' },
                                    { title: 'Single Pulse', price: `Γé╣${mess.dailyPrice || 80}`, priceValue: mess.dailyPrice || 80, type: 'DAILY', period: '/day', desc: '1 Cycle Trial Logic' },
                                ].map((plan) => (
                                    <button
                                        key={plan.title}
                                        onClick={() => setSelectedPlan(plan)}
                                        className={`w-full p-6 py-8 rounded-[1.5rem] border-2 text-left transition-all relative group ${selectedPlan?.title === plan.title
                                            ? 'border-primary-500 bg-primary-500/10 shadow-xl shadow-primary-500/20'
                                            : 'border-white/5 bg-white/[0.03] hover:border-white/20'
                                            }`}
                                    >
                                        {plan.popular && (
                                            <div className="absolute -top-3 right-6 bg-primary-500 text-white text-[8px] font-black uppercase tracking-widest px-4 py-1.5 rounded-full shadow-lg italic">
                                                Elite Choice
                                            </div>
                                        )}
                                        <div className="flex justify-between items-center mb-1">
                                            <span className="font-black text-white text-[11px] uppercase tracking-widest italic">{plan.title}</span>
                                            <div className="flex items-baseline">
                                                <span className="text-lg font-black text-primary-500 italic">{plan.price}</span>
                                            </div>
                                        </div>
                                        <p className="text-[8px] text-white/30 font-black uppercase tracking-widest">{plan.desc}</p>
                                    </button>
                                ))}
                            </div>

                            <Button
                                onClick={handleSubscribe}
                                disabled={subscribing}
                                className="w-full h-24 rounded-[2rem] text-sm font-black uppercase tracking-[0.4em] shadow-3xl shadow-primary-500/40 hover:scale-[1.05] transition-all bg-primary-500 text-white italic"
                                size="lg"
                            >
                                {subscribing ? 'Transmitting...' : 'Initiate Access'}
                            </Button>

                            <div className="mt-8 flex items-center justify-center gap-3 opacity-30">
                                <CircleCheck size={14} className="text-primary-500" />
                                <span className="text-[8px] font-black uppercase tracking-[0.2em] text-white">Razorpay Secure Protocol Active</span>
                            </div>
                        </Card>

                        <Card className="p-10 bg-[#0f172a] border border-white/10 rounded-[3rem] shadow-3xl text-white relative overflow-hidden">
                            <div className="absolute top-0 left-0 w-2 h-full bg-primary-500" />
                            <div className="flex items-center gap-6 mb-8">
                                <div className="p-4 bg-white/5 rounded-2xl border border-white/10 text-primary-500 shadow-2xl">
                                    <Clock size={24} />
                                </div>
                                <div className="space-y-1">
                                    <h4 className="text-[10px] font-black uppercase tracking-[0.4em] text-white/40 italic">Operational Status</h4>
                                    <p className="text-2xl font-black italic tracking-tighter">SEC <span className="text-primary-500">ACTIVE</span></p>
                                </div>
                            </div>
                            <div className="space-y-4">
                                <div className="flex justify-between items-center bg-white/5 p-5 rounded-2xl border border-white/5">
                                    <span className="text-[9px] font-black uppercase tracking-widest text-white/40 italic">Logistics Cycle</span>
                                    <span className="text-[10px] font-black uppercase tracking-widest">Daily 11:00 - 22:00</span>
                                </div>
                                <p className="text-[9px] font-black uppercase tracking-[0.2em] text-center text-white/20 italic pt-2">Zero Latency Meal Supply Guaranteed</p>
                            </div>
                        </Card>
                    </div>
                </div>
            </div>
        </Layout>
    );
};

export default MessDetailsPage;

import React, { useState, useEffect } from 'react';
import { Layout } from '../components/layout/Layout';
import { Card } from '../components/common/Card';
import { Button } from '../components/common/Button';
import {
    LayoutDashboard,
    Utensils,
    Users,
    TrendingUp,
    Settings,
    Save,
    Trash2,
    CircleCheck,
    MapPin,
    Phone,
    Image as ImageIcon,
    Clock,
    CreditCard,
    Calendar
} from 'lucide-react';
import { useAppSelector } from '../../hooks/redux';
import type { RootState } from '../../store';
import api from '../api/axiosInstance';
import { toast } from 'react-hot-toast';
import { BillingHistoryModal } from '../components/dashboard/BillingHistoryModal';
import { useNavigate } from 'react-router-dom';
import type { Mess, Subscription, Menu, MenuItem } from '../types/mess';

type Tab = 'overview' | 'menu' | 'subscribers' | 'settings';

const OwnerDashboardPage: React.FC = () => {
    const navigate = useNavigate();
    const { user } = useAppSelector((state: RootState) => state.auth);
    const [activeTab, setActiveTab] = useState<Tab>('overview');
    const [mess, setMess] = useState<Mess | null>(null);
    const [subscribers, setSubscribers] = useState<Subscription[]>([]);
    const [menus, setMenus] = useState<Menu[]>([]);
    const [revenue, setRevenue] = useState<number>(0);
    const [loading, setLoading] = useState(true);
    const [updating, setUpdating] = useState(false);
    const [savingMenu, setSavingMenu] = useState(false);
    const [selectedDay, setSelectedDay] = useState('Monday');
    const [isBillingModalOpen, setIsBillingModalOpen] = useState(false);
    const [subscription, setSubscription] = useState<Subscription | null>(null);


    // Form states
    const [messForm, setMessForm] = useState({
        name: '',
        description: '',
        address: '',
        cuisine: '',
        contact: '',
        images: [] as string[]
    });

    useEffect(() => {
        const fetchOwnerData = async () => {
            try {
                setLoading(true);
                const [messRes, subsRes, subStatusRes] = await Promise.all([
                    api.get('/messes/my'),
                    api.get('/subscriptions/subscribers'),
                    api.get('/subscriptions/status')
                ]);

                setMess(messRes.data.data);
                setMenus(messRes.data.data.menus || []);
                setSubscribers(subsRes.data.data);
                setRevenue(subsRes.data.totalRevenue || 0);
                setSubscription(subStatusRes.data.data);
                setMessForm({
                    name: messRes.data.data?.name || '',
                    description: messRes.data.data?.description || '',
                    address: messRes.data.data?.address || '',
                    cuisine: messRes.data.data?.cuisine || '',
                    contact: messRes.data.data?.contact || '',
                    images: messRes.data.data?.images || []
                });
            } catch (error) {
                console.error('Error fetching owner data:', error);
                toast.error('Failed to load dashboard data');
            } finally {
                setLoading(false);
            }
        };

        if (user && user.role === 'OWNER') fetchOwnerData();

        // Load Razorpay Script
        const script = document.createElement('script');
        script.src = 'https://checkout.razorpay.com/v1/checkout.js';
        script.async = true;
        document.body.appendChild(script);

        return () => {
            document.body.removeChild(script);
        };
    }, [user]);

    const handleUpdateMess = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            setUpdating(true);
            const response = await api.put('/messes/my', messForm);
            setMess(response.data.data);
            toast.success('Mess profile updated successfully');
        } catch (error) {
            toast.error('Failed to update mess profile');
        } finally {
            setUpdating(false);
        }
    };

    const handleMenuSave = async () => {
        try {
            setSavingMenu(true);
            await api.put('/messes/my/menu', { menus });
            toast.success('Weekly menu updated successfully!');
        } catch (error) {
            console.error('Error saving menu:', error);
            toast.error('Failed to save menu.');
        } finally {
            setSavingMenu(false);
        }
    };

    const handleItemChange = (day: string, itemIndex: number, field: string, value: string) => {
        setMenus(prevMenus => {
            const newMenus = [...prevMenus];
            const dayMenuIndex = newMenus.findIndex(m => m.day === day);

            if (dayMenuIndex !== -1) {
                const newItems = [...newMenus[dayMenuIndex].items];
                newItems[itemIndex] = { ...newItems[itemIndex], [field]: value };
                newMenus[dayMenuIndex] = { ...newMenus[dayMenuIndex], items: newItems };
            } else {
                // If day doesn't exist, create it and add the item
                newMenus.push({
                    day,
                    items: [{ name: '', type: 'Veg', [field]: value }]
                });
            }
            return newMenus;
        });
    };

    const handleAddItem = (day: string) => {
        setMenus(prevMenus => {
            const newMenus = [...prevMenus];
            const dayMenuIndex = newMenus.findIndex(m => m.day === day);

            if (dayMenuIndex !== -1) {
                newMenus[dayMenuIndex] = {
                    ...newMenus[dayMenuIndex],
                    items: [...newMenus[dayMenuIndex].items, { name: '', type: 'Veg' }]
                };
            } else {
                newMenus.push({
                    day,
                    items: [{ name: '', type: 'Veg' }]
                });
            }
            return newMenus;
        });
    };

    const handleRemoveItem = (day: string, itemIndex: number) => {
        setMenus(prevMenus => {
            const newMenus = [...prevMenus];
            const dayMenuIndex = newMenus.findIndex(m => m.day === day);

            if (dayMenuIndex !== -1) {
                const newItems = newMenus[dayMenuIndex].items.filter((_: MenuItem, idx: number) => idx !== itemIndex);
                newMenus[dayMenuIndex] = { ...newMenus[dayMenuIndex], items: newItems };
            }
            return newMenus;
        });
    };


    const renderOverview = () => (
        <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {[
                    { label: 'Total Revenue', value: `Γé╣${revenue.toLocaleString()}`, trend: '+12%', icon: <TrendingUp className="text-secondary" /> },
                    { label: 'Active Subscribers', value: subscribers.length.toString(), trend: '+5', icon: <Users className="text-primary" /> },
                    { label: 'Avg Rating', value: mess?.rating?.toFixed(1) || '0.0', trend: 'Global', icon: <Utensils className="text-accent" /> },
                ].map((stat, i) => (
                    <Card key={i} className="p-6">
                        <div className="flex justify-between items-start mb-4">
                            <div className="p-3 bg-gray-50 rounded-xl">{stat.icon}</div>
                            <span className={`text-xs font-bold px-2 py-1 rounded-full ${stat.trend.startsWith('+') ? 'bg-green-100 text-green-600' : 'bg-gray-100 text-gray-500'}`}>
                                {stat.trend}
                            </span>
                        </div>
                        <p className="text-gray-400 text-sm font-medium">{stat.label}</p>
                        <p className="text-3xl font-black mt-1">{stat.value}</p>
                    </Card>
                ))}
            </div>

            {/* Subscription Status Card */}
            <section className="space-y-4">
                <h2 className="text-xl font-bold">Subscription Status</h2>
                <Card className="p-6 overflow-hidden border-2 border-primary/20 bg-primary/5">
                    <div className="flex flex-col md:flex-row items-center justify-between gap-6">
                        <div className="flex items-center space-x-6">
                            <div className={`p-4 rounded-2xl ${subscription?.status === 'trial' ? 'bg-orange-100 text-orange-600' :
                                subscription?.status === 'active' ? 'bg-green-100 text-green-600' :
                                    'bg-red-100 text-red-600'
                                }`}>
                                <CreditCard size={32} />
                            </div>
                            <div>
                                <div className="flex items-center space-x-3 mb-1">
                                    <h3 className="text-lg font-black uppercase tracking-tight">
                                        {subscription?.status === 'trial' ? '60-Day Free Trial' : 'Elite Listing Plan'}
                                    </h3>
                                    <span className={`text-[10px] font-black px-2 py-1 rounded-lg uppercase ${subscription?.status === 'trial' ? 'bg-orange-500 text-white' :
                                        subscription?.status === 'active' ? 'bg-green-500 text-white' :
                                            'bg-red-500 text-white'
                                        }`}>
                                        {subscription?.status || 'No Plan'}
                                    </span>
                                </div>
                                <div className="flex items-center space-x-4 text-sm font-bold text-gray-500">
                                    {subscription?.status === 'trial' && (
                                        <div className="flex items-center text-orange-600">
                                            <Clock size={16} className="mr-1" />
                                            <span>
                                                {(() => {
                                                    if (!subscription?.trial_end) return '60 days remaining';
                                                    const end = new Date(subscription.trial_end);
                                                    const now = new Date();
                                                    const diff = Math.ceil((end.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
                                                    return `${Math.max(0, diff)} days remaining`;
                                                })()}
                                            </span>
                                        </div>
                                    )}
                                    {subscription?.subscription_end && (
                                        <div className="flex items-center">
                                            <Calendar size={16} className="mr-1" />
                                            <span>Next billing: {new Date(subscription.subscription_end).toLocaleDateString()}</span>
                                        </div>
                                    )}
                                    <div className="flex items-center">
                                        <CircleCheck size={16} className="mr-1 text-green-500" />
                                        <span>Status: {subscription?.status?.toUpperCase() || 'INACTIVE'}</span>
                                    </div>
                                </div>
                            </div>
                        </div>
                        <div className="flex space-x-3">
                            {subscription?.status !== 'active' && (
                                <>
                                    <Button
                                        className="rounded-xl px-8 shadow-lg shadow-primary/20"
                                        onClick={() => navigate('/owner/subscribe')}
                                        isLoading={updating}
                                    >
                                        Subscribe (Γé╣499/mo)
                                    </Button>
                                </>
                            )}
                            <Button
                                variant="outline"
                                className="rounded-xl border-gray-200"
                                onClick={() => setIsBillingModalOpen(true)}
                            >
                                Billing History
                            </Button>
                        </div>
                    </div>
                </Card>
            </section>

            <section className="space-y-4">
                <h2 className="text-xl font-bold">Quick Activity</h2>
                <Card className="p-0 overflow-hidden">
                    <div className="divide-y divide-gray-100">
                        {subscribers.slice(0, 5).map(sub => (
                            <div key={sub.id} className="p-4 flex items-center justify-between hover:bg-gray-50 transition-colors">
                                <div className="flex items-center space-x-3">
                                    <div className="w-10 h-10 rounded-full bg-primary/10 flex items-center justify-center text-primary font-bold">
                                        {sub.user?.name.charAt(0) || '?'}
                                    </div>
                                    <div>
                                        <p className="font-bold text-sm">{sub.user?.name || 'Unknown Student'}</p>
                                        <p className="text-xs text-gray-400">{sub.plan_type} Plan ΓÇó {sub.created_at ? new Date(sub.created_at).toLocaleDateString() : 'N/A'}</p>
                                    </div>
                                </div>
                                <span className="text-[10px] font-black uppercase text-green-500 bg-green-50 px-2 py-1 rounded-lg">Active</span>
                            </div>
                        ))}
                    </div>
                </Card>
            </section>
        </div>
    );

    const renderMenuManagement = () => (
        <div className="space-y-6">
            <div className="flex justify-between items-center mb-10">
                <div className="space-y-1">
                    <h2 className="text-3xl font-black text-dark-900">Menu Schedule</h2>
                    <p className="text-gray-500 text-sm font-medium uppercase tracking-widest">Manage your weekly specials</p>
                </div>
                <Button
                    onClick={handleMenuSave}
                    isLoading={savingMenu}
                    className="bg-primary hover:bg-primary/90 px-10 py-6 rounded-2xl font-black uppercase tracking-widest"
                >
                    Save Weekly Menu
                </Button>
            </div>

            <div className="flex gap-3 overflow-x-auto pb-6 mb-10 scrollbar-hide">
                {['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'].map((day) => (
                    <button
                        key={day}
                        onClick={() => setSelectedDay(day)}
                        className={`px-8 py-4 rounded-2xl text-xs font-black uppercase tracking-widest transition-all whitespace-nowrap border-2 ${selectedDay === day
                            ? 'bg-primary text-white border-primary shadow-[0_0_30px_rgba(255,69,0,0.2)]'
                            : 'bg-gray-50 text-gray-500 border-transparent hover:bg-gray-100 hover:text-gray-700'
                            }`}
                    >
                        {day}
                    </button>
                ))}
            </div>

            <div className="space-y-6">
                {menus.find(m => m.day === selectedDay)?.items.map((item: MenuItem, idx: number) => (
                    <div key={idx} className="bg-white p-8 rounded-3xl flex flex-col md:flex-row gap-6 items-center group transition-all hover:bg-gray-50 relative border border-gray-100">
                        <div className="flex-1 w-full space-y-3">
                            <label className="text-[10px] font-black uppercase tracking-widest text-gray-400">Item Name</label>
                            <input
                                type="text"
                                value={item.name}
                                onChange={(e) => handleItemChange(selectedDay, idx, 'name', e.target.value)}
                                className="w-full bg-gray-50 border border-gray-100 p-6 rounded-2xl text-dark-900 outline-none focus:ring-2 focus:ring-primary transition-all"
                                placeholder="Enter item name..."
                            />
                        </div>
                        <div className="w-full md:w-64 space-y-3">
                            <label className="text-[10px] font-black uppercase tracking-widest text-gray-400">Category</label>
                            <select
                                value={item.type}
                                onChange={(e) => handleItemChange(selectedDay, idx, 'type', e.target.value)}
                                className="w-full bg-gray-50 border border-gray-100 p-6 rounded-2xl text-dark-900 outline-none focus:ring-2 focus:ring-primary transition-all appearance-none"
                            >
                                <option value="Veg" className="bg-white">Veg</option>
                                <option value="Non-Veg" className="bg-white">Non-Veg</option>
                            </select>
                        </div>
                        <div className="pt-6 md:pt-8 w-full md:w-auto">
                            <button
                                onClick={() => handleRemoveItem(selectedDay, idx)}
                                className="w-full md:w-auto p-6 bg-red-500/10 text-red-500 rounded-2xl hover:bg-red-500 hover:text-white transition-all border border-red-500/20"
                            >
                                Remove
                            </button>
                        </div>
                    </div>
                ))}

                <button
                    onClick={() => handleAddItem(selectedDay)}
                    className="w-full border-2 border-dashed border-gray-200 p-10 rounded-3xl text-sm font-black uppercase tracking-widest text-gray-400 hover:border-primary hover:text-primary hover:bg-primary/5 transition-all group"
                >
                    <span className="group-hover:scale-110 transition-transform inline-block">+ Add Item to {selectedDay}</span>
                </button>
            </div>
        </div>
    );

    const renderSubscribers = () => (
        <div className="space-y-6">
            <h2 className="text-xl font-bold">Active Subscribers ({subscribers.length})</h2>
            <Card className="p-0 overflow-hidden">
                <table className="w-full text-left">
                    <thead className="bg-gray-50 border-b border-gray-100">
                        <tr>
                            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase">Student</th>
                            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase">Plan</th>
                            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase">Started</th>
                            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase">Status</th>
                            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {subscribers.map(sub => (
                            <tr key={sub.id} className="hover:bg-gray-50 transition-colors">
                                <td className="px-6 py-4">
                                    <div className="flex items-center space-x-3">
                                        <div className="w-8 h-8 rounded-full bg-gray-200" />
                                        <div>
                                            <p className="font-bold text-sm">{sub.user?.name || 'Unknown'}</p>
                                            <p className="text-xs text-gray-400">{sub.user?.email || 'N/A'}</p>
                                        </div>
                                    </div>
                                </td>
                                <td className="px-6 py-4">
                                    <p className="text-sm font-medium">{sub.plan_type}</p>
                                </td>
                                <td className="px-6 py-4 text-sm text-gray-500">
                                    {sub.created_at ? new Date(sub.created_at).toLocaleDateString() : 'N/A'}
                                </td>
                                <td className="px-6 py-4">
                                    <span className="text-[10px] font-bold px-2 py-1 bg-green-100 text-green-600 rounded-lg uppercase">Active</span>
                                </td>
                                <td className="px-6 py-4">
                                    <Button variant="ghost" size="sm" className="text-red-500 hover:bg-red-50">
                                        <Trash2 size={16} />
                                    </Button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </Card>
        </div>
    );

    const renderSettings = () => (
        <div className="space-y-6">
            <h2 className="text-xl font-bold">Mess Profile Settings</h2>
            <Card className="p-8">
                <form onSubmit={handleUpdateMess} className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="space-y-2">
                            <label className="text-sm font-bold text-gray-600">Mess Name</label>
                            <input
                                type="text"
                                value={messForm.name}
                                onChange={e => setMessForm({ ...messForm, name: e.target.value })}
                                className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all"
                                placeholder="Business Name"
                            />
                        </div>
                        <div className="space-y-2">
                            <label className="text-sm font-bold text-gray-600">Cuisine Types</label>
                            <input
                                type="text"
                                value={messForm.cuisine}
                                onChange={e => setMessForm({ ...messForm, cuisine: e.target.value })}
                                className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all"
                                placeholder="e.g. Maharashtrian, North Indian"
                            />
                        </div>
                        <div className="md:col-span-2 space-y-2">
                            <label className="text-sm font-bold text-gray-600">Description</label>
                            <textarea
                                rows={3}
                                value={messForm.description}
                                onChange={e => setMessForm({ ...messForm, description: e.target.value })}
                                className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all"
                                placeholder="Tell students about your kitchen and services..."
                            />
                        </div>
                        <div className="space-y-2">
                            <label className="text-sm font-bold text-gray-600">Address</label>
                            <div className="relative">
                                <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                                <input
                                    type="text"
                                    value={messForm.address}
                                    onChange={e => setMessForm({ ...messForm, address: e.target.value })}
                                    className="w-full pl-12 pr-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all"
                                    placeholder="Full location"
                                />
                            </div>
                        </div>
                        <div className="space-y-2">
                            <label className="text-sm font-bold text-gray-600">Contact Number</label>
                            <div className="relative">
                                <Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                                <input
                                    type="text"
                                    value={messForm.contact}
                                    onChange={e => setMessForm({ ...messForm, contact: e.target.value })}
                                    className="w-full pl-12 pr-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all"
                                    placeholder="Business phone"
                                />
                            </div>
                        </div>
                    </div>

                    <div className="pt-6 border-t border-gray-100 flex justify-end">
                        <Button type="submit" isLoading={updating} className="rounded-xl px-12">
                            <Save size={18} className="mr-2" /> Save Changes
                        </Button>
                    </div>
                </form>
            </Card>
        </div>
    );

    return (
        <Layout>
            <div className="bg-dark text-white py-12 relative overflow-hidden">
                <div className="absolute inset-0 bg-primary opacity-5 animate-pulse" />
                <div className="container mx-auto px-4 relative">
                    <div className="flex flex-col md:row items-center justify-between gap-6">
                        <div className="space-y-2">
                            <h1 className="text-4xl font-heading font-black tracking-tighter">OWNER DASHBOARD</h1>
                            <div className="flex items-center space-x-2 text-primary">
                                <CircleCheck size={16} />
                                <p className="text-sm font-bold uppercase tracking-widest">{mess?.name || 'Loading...'}</p>
                            </div>
                        </div>
                        <div className="flex space-x-3">
                            <Button variant="outline" size="sm" className="rounded-xl border-white/20 text-white hover:bg-white/10 backdrop-blur-sm">
                                <ImageIcon size={18} className="mr-2" /> Manage Gallery
                            </Button>
                        </div>
                    </div>
                </div>
            </div>

            <div className="container mx-auto px-4 -mt-10 pb-20">
                <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
                    {/* Navigation */}
                    <div className="lg:col-span-1">
                        <Card className="p-2 space-y-1 sticky top-24 shadow-2xl shadow-primary/5 dark:bg-dark-card rounded-2xl">
                            {[
                                { id: 'overview', icon: <LayoutDashboard size={20} />, label: 'Overview' },
                                { id: 'menu', icon: <Utensils size={20} />, label: 'Menu Schedule' },
                                { id: 'subscribers', icon: <Users size={20} />, label: 'Subscribers' },
                                { id: 'settings', icon: <Settings size={20} />, label: 'Profile Settings' },
                            ].map((item) => (
                                <button
                                    key={item.id}
                                    onClick={() => setActiveTab(item.id as Tab)}
                                    className={`w-full flex items-center space-x-3 px-5 py-4 rounded-xl transition-all font-bold text-sm ${activeTab === item.id
                                        ? 'bg-primary text-white shadow-xl shadow-primary/30'
                                        : 'text-gray-500 hover:bg-gray-50'
                                        }`}
                                >
                                    {item.icon}
                                    <span>{item.label}</span>
                                </button>
                            ))}
                        </Card>
                    </div>

                    {/* Content Area */}
                    <div className="lg:col-span-3">
                        {loading ? (
                            <div className="space-y-6">
                                <div className="h-40 bg-gray-50 rounded-2xl animate-pulse" />
                                <div className="h-80 bg-gray-50 rounded-2xl animate-pulse" />
                            </div>
                        ) : (
                            <>
                                {activeTab === 'overview' && renderOverview()}
                                {activeTab === 'menu' && renderMenuManagement()}
                                {activeTab === 'subscribers' && renderSubscribers()}
                                {activeTab === 'settings' && renderSettings()}
                            </>
                        )}
                    </div>
                </div>
            </div>

            <BillingHistoryModal
                isOpen={isBillingModalOpen}
                onClose={() => setIsBillingModalOpen(false)}
            />
        </Layout>
    );
};

export default OwnerDashboardPage;

import React, { useState, useEffect, useCallback } from 'react';
import { Layout } from '../components/layout/Layout';
import { Card } from '../components/common/Card';
import { Button } from '../components/common/Button';
import {
    User, Mail, Phone, Calendar, Camera, ShieldCheck,
    Save, ArrowLeft, CircleCheck, Clock, Smartphone,
    LogOut, Trash2, Key, History, Edit3, UserCheck,
    Zap, ExternalLink
} from 'lucide-react';
import { useAppSelector, useAppDispatch } from '../../hooks/redux';
import type { RootState } from '../../store';
import Seo from '../components/common/Seo';
import { motion, AnimatePresence } from 'framer-motion';
import api, { getImageUrl } from '../api/axiosInstance';
import { updateAuthUser } from '../../store/slices/authSlice';
import type { Activity } from '../types/mess';
import { AxiosError } from 'axios';

type ActiveTab = 'personal' | 'security' | 'activity';

const ProfilePage: React.FC = () => {
    const { user } = useAppSelector((state: RootState) => state.auth);
    const dispatch = useAppDispatch();
    const [activeTab, setActiveTab] = useState<ActiveTab>('personal');
    const [isEditing, setIsEditing] = useState(false);
    const [formData, setFormData] = useState({
        name: user?.name || '',
        phone: user?.phone || '',
    });
    const [passwordData, setPasswordData] = useState({
        currentPassword: '',
        newPassword: '',
        confirmPassword: ''
    });
    const [activities, setActivities] = useState<Activity[]>([]);
    const [loadingActivities, setLoadingActivities] = useState(false);
    const [message, setMessage] = useState({ type: '', text: '' });

    const fetchProfile = useCallback(async () => {
        try {
            const response = await api.get('/users/profile');
            if (response.data.success) {
                const userData = response.data.user;
                dispatch(updateAuthUser(userData));
                setFormData({
                    name: userData.name || '',
                    phone: userData.phone || '',
                });
            }
        } catch (error) {
            console.error('Error fetching profile:', error);
        }
    }, [dispatch]);

    const fetchActivity = useCallback(async () => {
        setLoadingActivities(true);
        try {
            const response = await api.get('/users/activity');
            setActivities(response.data.data);
        } catch (error) { // Changed 'err' to 'error' for consistency and removed 'toast.error' as it's not imported
            console.error('Error fetching activity:', error);
        } finally {
            setLoadingActivities(false);
        }
    }, []);

    useEffect(() => {
        fetchProfile();
    }, [fetchProfile]);

    useEffect(() => {
        if (activeTab === 'activity') {
            fetchActivity();
        }
    }, [activeTab, fetchActivity]);

    const handleSave = async () => {
        try {
            const response = await api.put('/users/profile', formData);
            if (response.data.success) {
                dispatch(updateAuthUser(response.data.user));
                setMessage({ type: 'success', text: 'Profile updated successfully!' });
                setIsEditing(false);
            }
        } catch (error: any) {
            setMessage({ type: 'error', text: error.response?.data?.message || 'Update failed' });
        }
    };

    const handlePasswordChange = async () => {
        if (passwordData.newPassword !== passwordData.confirmPassword) {
            return setMessage({ type: 'error', text: 'Passwords do not match' });
        }
        try {
            await api.post('/users/change-password', passwordData);
            setMessage({ type: 'success', text: 'Password changed successfully!' });
            setPasswordData({ currentPassword: '', newPassword: '', confirmPassword: '' });
        } catch (err) {
            const error = err as AxiosError<{ message: string }>;
            setMessage({ type: 'error', text: error.response?.data?.message || 'Password change failed' });
        }
    };

    const triggerAvatarUpload = () => {
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = 'image/*';
        input.onchange = async (e: Event) => {
            const target = e.target as HTMLInputElement;
            const file = target.files?.[0];
            if (file) {
                const formData = new FormData();
                formData.append('avatar', file);
                try {
                    const response = await api.post('/users/upload-avatar', formData, {
                        headers: { 'Content-Type': 'multipart/form-data' }
                    });
                    if (response.data.success) {
                        const newAvatar = response.data.profile_image;
                        // Update profile with new image path
                        const updateRes = await api.put('/users/profile', {
                            name: user?.name,
                            phone: user?.phone,
                            profile_image: newAvatar
                        });
                        if (updateRes.data.success) {
                            dispatch(updateAuthUser(updateRes.data.user));
                            setMessage({ type: 'success', text: 'Avatar updated!' });
                        }
                    }
                } catch (err) {
                    setMessage({ type: 'error', text: 'Upload failed' });
                }
            }
        };
        input.click();
    };

    // Calculate profile completion
    const completionPercentage = (() => {
        let score = 0;
        if (user?.name) score += 25;
        if (user?.email) score += 25;
        if (user?.phone) score += 25;
        if (user?.profile_image) score += 25;
        return score;
    })();

    const joinDate = user?.created_at ? new Date(user.created_at).toLocaleDateString('en-US', {
        month: 'long',
        year: 'numeric'
    }) : 'March 2026';

    return (
        <Layout>
            <Seo
                title="Profile Discovery | MessWalha Dashboard"
                description="Manage your professional mess subscription profile"
            />

            <div className="min-h-screen bg-[#0f172a] relative overflow-hidden pt-32 pb-24">
                {/* Futuristic Background Elements */}
                <div className="absolute top-0 right-0 w-[800px] h-[800px] bg-primary-500/10 rounded-full blur-[150px] -mr-64 -mt-64 pointer-events-none" />
                <div className="absolute bottom-0 left-0 w-[600px] h-[600px] bg-indigo-500/10 rounded-full blur-[120px] -ml-64 -mb-64 pointer-events-none" />
                <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 pointer-events-none" />

                <div className="container mx-auto px-4 relative z-10">
                    {/* Header Breadcrumb */}
                    <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-12 gap-6">
                        <motion.button
                            initial={{ x: -20, opacity: 0 }}
                            animate={{ x: 0, opacity: 1 }}
                            onClick={() => window.history.back()}
                            className="flex items-center text-white/40 hover:text-primary-500 transition-all font-black uppercase tracking-[0.3em] text-[10px] group"
                        >
                            <ArrowLeft size={16} className="mr-3 group-hover:-translate-x-2 transition-transform" />
                            Discover Dashboard
                        </motion.button>

                        <AnimatePresence>
                            {message.text && (
                                <motion.div
                                    initial={{ y: -20, opacity: 0 }}
                                    animate={{ y: 0, opacity: 1 }}
                                    exit={{ y: -20, opacity: 0 }}
                                    className={`px-6 py-3 rounded-2xl border ${message.type === 'success' ? 'bg-green-500/10 border-green-500/20 text-green-500' : 'bg-red-500/10 border-red-500/20 text-red-500'} text-[10px] font-black uppercase tracking-widest`}
                                >
                                    {message.text}
                                </motion.div>
                            )}
                        </AnimatePresence>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
                        {/* Sidebar Column */}
                        <div className="lg:col-span-4 space-y-8">
                            <motion.div
                                initial={{ y: 30, opacity: 0 }}
                                animate={{ y: 0, opacity: 1 }}
                            >
                                <Card className="bg-white/5 backdrop-blur-3xl border-white/10 p-10 rounded-[3rem] shadow-3xl relative overflow-hidden text-center group">
                                    <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-primary-500 to-indigo-600" />

                                    <div className="relative inline-block mb-10">
                                        <div className="w-40 h-40 rounded-[2.5rem] bg-gradient-to-br from-primary-500 to-indigo-600 p-1 shadow-2xl shadow-primary-500/20">
                                            <div className="w-full h-full rounded-[2.3rem] overflow-hidden bg-dark-900 flex items-center justify-center">
                                                {user?.profile_image ? (
                                                    <img src={getImageUrl(user.profile_image)} alt={user.name} className="w-full h-full object-cover" />
                                                ) : (
                                                    <span className="text-6xl font-black text-white italic">{user?.name?.charAt(0)}</span>
                                                )}
                                            </div>
                                        </div>
                                        <motion.button
                                            whileHover={{ scale: 1.1 }}
                                            whileTap={{ scale: 0.9 }}
                                            onClick={triggerAvatarUpload}
                                            className="absolute bottom-0 right-0 p-4 bg-white dark:bg-dark-900 rounded-[1.5rem] shadow-2xl text-primary-500 hover:text-white hover:bg-primary-500 transition-all border border-white/10"
                                        >
                                            <Camera size={20} />
                                        </motion.button>
                                    </div>

                                    <div className="space-y-4">
                                        <div className="space-y-1">
                                            <h2 className="text-3xl font-black tracking-tighter text-white italic truncate">{user?.name}</h2>
                                            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-primary-500">
                                                {user?.role === 'OWNER' ? 'Mess Partner' : 'User Account'}
                                            </p>
                                        </div>

                                        <div className="flex flex-col items-center gap-3 pt-6">
                                            <div className="flex items-center gap-2 px-4 py-2 bg-indigo-500/10 rounded-full border border-indigo-500/20">
                                                <UserCheck size={14} className="text-indigo-400" />
                                                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Verified User</span>
                                            </div>
                                            <div className="flex items-center gap-2 px-4 py-2 bg-primary-500/10 rounded-full border border-primary-500/20">
                                                <Zap size={14} className="text-primary-500" />
                                                <span className="text-[10px] font-black text-primary-500 uppercase tracking-widest">Active Subscription</span>
                                            </div>
                                        </div>

                                        <div className="pt-8 space-y-4 border-t border-white/5">
                                            <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest text-white/40">
                                                <span>Profile Completion</span>
                                                <span>{completionPercentage}%</span>
                                            </div>
                                            <div className="h-2 w-full bg-white/5 rounded-full overflow-hidden p-[2px]">
                                                <motion.div
                                                    initial={{ width: 0 }}
                                                    animate={{ width: `${completionPercentage}%` }}
                                                    className="h-full bg-gradient-to-r from-primary-500 to-indigo-600 rounded-full shadow-[0_0_15px_rgba(255,100,0,0.4)]"
                                                />
                                            </div>
                                        </div>

                                        <div className="flex items-center justify-between pt-6 text-[10px] font-black uppercase tracking-widest text-white/30">
                                            <span className="flex items-center gap-2"><Calendar size={12} /> Joined: {joinDate}</span>
                                            <span className="flex items-center gap-2"><Clock size={12} /> 12:45 PM</span>
                                        </div>
                                    </div>
                                </Card>
                            </motion.div>

                            <motion.div
                                initial={{ y: 30, opacity: 0 }}
                                animate={{ y: 0, opacity: 1 }}
                                transition={{ delay: 0.1 }}
                                className="space-y-2"
                            >
                                {[
                                    { id: 'personal', icon: User, label: 'Profile Information' },
                                    { id: 'security', icon: ShieldCheck, label: 'Security' },
                                    { id: 'activity', icon: History, label: 'Activity' }
                                ].map(tab => (
                                    <button
                                        key={tab.id}
                                        onClick={() => setActiveTab(tab.id as ActiveTab)}
                                        className={`w-full flex items-center justify-between px-8 py-5 rounded-[2rem] transition-all duration-500 font-black uppercase tracking-widest text-[10px] border ${activeTab === tab.id ? 'bg-primary-500 border-primary-400 text-white shadow-3xl shadow-primary-500/30' : 'bg-white/5 border-white/5 text-white/40 hover:bg-white/10 hover:text-white'}`}
                                    >
                                        <div className="flex items-center gap-4">
                                            <tab.icon size={18} />
                                            <span>{tab.label}</span>
                                        </div>
                                        <ArrowLeft size={16} className="rotate-180 opacity-40" />
                                    </button>
                                ))}
                            </motion.div>
                        </div>

                        {/* Main Content Column */}
                        <div className="lg:col-span-8">
                            <motion.div
                                key={activeTab}
                                initial={{ x: 20, opacity: 0 }}
                                animate={{ x: 0, opacity: 1 }}
                                transition={{ duration: 0.4 }}
                            >
                                <Card className="bg-white/5 backdrop-blur-3xl border-white/10 p-10 md:p-16 rounded-[3rem] shadow-3xl">
                                    <AnimatePresence mode="wait">
                                        {activeTab === 'personal' && (
                                            <motion.div
                                                key="personal-tab"
                                                initial={{ opacity: 0 }}
                                                animate={{ opacity: 1 }}
                                                exit={{ opacity: 0 }}
                                                className="space-y-12"
                                            >
                                                <div className="flex justify-between items-center">
                                                    <div>
                                                        <h3 className="text-4xl font-black text-white italic tracking-tighter">Profile <span className="text-primary-500">Information</span></h3>
                                                        <p className="text-[10px] font-black uppercase tracking-[0.3em] text-white/30 mt-2">View and update your profile details</p>
                                                    </div>
                                                    {!isEditing && (
                                                        <Button
                                                            variant="outline"
                                                            onClick={() => setIsEditing(true)}
                                                            className="rounded-full px-10 h-16 border-white/10 hover:bg-white/5 font-black uppercase tracking-widest text-[10px]"
                                                        >
                                                            <Edit3 size={18} className="mr-3" /> Edit Profile
                                                        </Button>
                                                    )}
                                                </div>

                                                <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-10">
                                                    {[
                                                        { label: 'Full Name', key: 'name', icon: User, placeholder: 'Enter Name' },
                                                        { label: 'Email Address', key: 'email', icon: Mail, disabled: true },
                                                        { label: 'Phone Number', key: 'phone', icon: Phone, placeholder: '+91 XXXXX XXXXX' },
                                                        { label: 'Join Date', key: 'joined', icon: Calendar, disabled: true, value: joinDate }
                                                    ].map((field) => (
                                                        <div key={field.key} className="space-y-4">
                                                            <label className="text-[10px] font-black uppercase tracking-[0.3em] text-white/30 ml-2">{field.label}</label>
                                                            <div className="relative group">
                                                                <div className="absolute left-6 top-1/2 -translate-y-1/2 text-primary-500 z-10">
                                                                    <field.icon size={18} />
                                                                </div>
                                                                <input
                                                                    type="text"
                                                                    disabled={field.disabled || !isEditing}
                                                                    value={field.value || (field.key === 'email' ? user?.email : (formData as Record<string, string>)[field.key])}
                                                                    onChange={e => setFormData({ ...formData, [field.key]: e.target.value })}
                                                                    placeholder={field.placeholder}
                                                                    className="w-full bg-white/[0.03] backdrop-blur-xl border border-white/10 rounded-[2rem] pl-16 pr-8 py-5 text-white font-black uppercase tracking-widest text-[10px] focus:ring-2 focus:ring-primary-500/40 focus:bg-white/[0.07] outline-none transition-all disabled:opacity-50 disabled:cursor-not-allowed group-hover:border-white/20"
                                                                />
                                                            </div>
                                                        </div>
                                                    ))}
                                                </div>

                                                {isEditing && (
                                                    <motion.div
                                                        initial={{ y: 20, opacity: 0 }}
                                                        animate={{ y: 0, opacity: 1 }}
                                                        className="flex flex-col sm:flex-row gap-4 pt-10 border-t border-white/5"
                                                    >
                                                        <button
                                                            onClick={handleSave}
                                                            className="flex-1 h-20 bg-gradient-to-r from-primary-500 to-primary-600 rounded-[2rem] text-white font-black uppercase tracking-[0.2em] text-xs shadow-2xl shadow-primary-500/40 hover:scale-[1.02] transition-all flex items-center justify-center gap-3 relative overflow-hidden group"
                                                        >
                                                            <div className="absolute inset-0 bg-white/20 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-1000" />
                                                            <Save size={20} /> Save Changes
                                                        </button>
                                                        <button
                                                            onClick={() => setIsEditing(false)}
                                                            className="flex-1 h-20 bg-white/5 border border-white/10 rounded-[2rem] text-white/50 font-black uppercase tracking-[0.2em] text-xs hover:text-white hover:bg-white/10 transition-all flex items-center justify-center gap-3"
                                                        >
                                                            Cancel
                                                        </button>
                                                    </motion.div>
                                                )}

                                                <div className="p-10 bg-indigo-500/5 rounded-[2.5rem] border border-indigo-500/10 space-y-4">
                                                    <div className="flex items-center gap-4 text-indigo-400">
                                                        <CircleCheck size={20} />
                                                        <span className="text-xs font-black uppercase tracking-widest italic">Compliance Status: Fully Aligned</span>
                                                    </div>
                                                    <p className="text-[10px] text-white/30 font-medium leading-relaxed italic">
                                                        Your data is encrypted using 256-bit AES protocols and stored across decentralized nodes for maximum privacy and resilience.
                                                    </p>
                                                </div>
                                            </motion.div>
                                        )}

                                        {activeTab === 'security' && (
                                            <motion.div
                                                key="security-tab"
                                                initial={{ opacity: 0 }}
                                                animate={{ opacity: 1 }}
                                                exit={{ opacity: 0 }}
                                                className="space-y-12"
                                            >
                                                <div className="space-y-2">
                                                    <h3 className="text-4xl font-black text-white italic tracking-tighter">Security <span className="text-primary-500">Fortress</span></h3>
                                                    <p className="text-[10px] font-black uppercase tracking-[0.3em] text-white/30">Protocol management and access control</p>
                                                </div>

                                                <div className="grid grid-cols-1 gap-10">
                                                    <div className="space-y-8 p-10 bg-white/5 rounded-[2.5rem] border border-white/5">
                                                        <div className="flex items-center gap-4">
                                                            <div className="w-12 h-12 rounded-2xl bg-primary-500/20 flex items-center justify-center text-primary-500">
                                                                <Key size={24} />
                                                            </div>
                                                            <h4 className="text-xl font-black text-white italic tracking-tight">Credential Rotation</h4>
                                                        </div>
